insert into questions (subject, text, options, correct) values
  ('Doenças Infecciosas e Parasitárias', 'Em relação à raiva as afirmativas estão corretas, EXCETO:', '["A cegueira pode ser um sinal clínico, mas não é comum.","Os sinais clínicos progressivos são típicos da enfermidade, descartando a necessidade de diagnóstico diferencial com outras doenças.","Os sinais de medula espinhal são frequentemente observados.","O vírus se replica no local de inoculação em um animal recentemente mordido e posteriormente atinge o SNC por fluxo axonal retrógrado.","O período de incubação é bastante variável e pode se estender de uma semana até 3 meses, podendo ser tão longo quanto 6 meses."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Sobre a febre catarral maligna assinale a alternativa INCORRETA:', '["A histopatologia tecidual constitui o melhor meio de confirmação de uma suspeita de FCM.","Bovinos e ovinos têm de interagir ou ficar em pastos comuns para que a doença, seja na forma esporádica ou epidêmica, apareça nos bovinos.","O vírus da FCM ocasiona doença inflamatória multissistêmica e os sinais clínicos resultam de uma vasculite severa em todos os órgãos.","A FCM crônica se caracteriza por um curso clínico longo (geralmente de semanas) de febre alta, lesões erosivas e ulcerativas de mucosa, uveíte bilateral, lesões cutâneas hiperqueratóticas, linfadenopatia e lesões digitais.","A estomatite vesicular, febre aftosa, diarreia viral bovina e língua azul devem ser incluídas no diagnóstico diferencial de febre catarral maligna."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Sobre a actinobacilose e actinomicose as afirmações estão corretas, EXCETO:', '["O Actinobacillus lignieresi é um organismo comensal normal na flora oral dos bovinos.","A língua de madeira, uma infecção de tecido mole da língua dos bovinos, constitui o exemplo clássico da actinobacilose, mas também são comuns granulomas de tecido mole ao redor da cabeça, do pescoço ou em outras áreas corporais.","O Actinomyces bovis é um habitante normal da flora oral dos bovinos e do trato digestivo dos bovinos.","No tratamento da actinobacilose e actinomicose deve-se incluir antimicrobianos e iodeto de sódio intravenoso em solução a 20%.","Uma osteomielite proliferativa da mandíbula e linfadenite regional caracteriza a actinobacilose."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'O botulismo ocorre em diferentes regiões do País, sendo causado pela ingestão de toxinas pré-formadas existentes em carcaças de animais, alimentos ou água. Assinale a alternativa que mais se aplica a essa doença:', '["As manifestações clínicas do botulismo são secundárias à paralisia flácida associada à ação da toxina na placa neuro-muscular.","Na necropsia dos animais mortos por botulismo as lesões observadas são sugestivas da enfermidade.","A paresia de língua, sinal importante do botulismo, demonstra que há comprometimento no tronco cerebral.","O envio de fragmentos de órgãos da cavidade abdominal formolizados é importante para o diagnóstico de botulismo.","Não são observadas alterações macroscópicas ou histológicas em animais mortos por botulismo, exceto encefalite não supurativa discreta."]'::jsonb, 0),
  ('Doenças Infecciosas e Parasitárias', 'Sobre as miosites clostridiais (carbúnculo sintomático e edema maligno) as afirmativas estão corretas, EXCETO:', '["A patogênese do carbúnculo sintomático não é completamente compreendida. Uma possibilidade é que os animais no pastejo ingiram esporos de C. chauvoei que são transportados para o músculo através do sangue e permanecem dormentes até que as condições locais favoreçam a multiplicação bacteriana.","O edema maligno ocorre quando esporos de C. septicum, mas também de C. novyi, C. sordelli ou C. chauvoei são introduzidos no tecido por feridas penetrantes, frequentemente resultantes de vacinação, descorna, castração e tosquia.","De forma semelhante ao botulismo e enterotoxemia, a detecção das toxinas produzidas pelos agentes envolvidos é imprescindível para o diagnóstico.","No carbúnculo sintomático os animais apresentam febre, anorexia, depressão e claudicação quando o membro é atingido. As massas musculares acometidas mostram-se crepitantes, aumentadas de volume e a morte usualmente ocorre entre 12 a 96 horas após o início dos sinais clínicos.","Embora os agentes das mionecroses sejam sensíveis à penicilina e outros antibióticos de largo espectro, estes são de pouca eficiência, pois em geral o curso da doença é superagudo ou agudo."]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'Em relação à tuberculose bovina as afirmativas são corretas, EXCETO:', '["A infecção com o Mycobacterium pode ocorrer após inalação ou ingestão por parte de bovinos susceptíveis. Após a infecção, formam-se lesões primárias no órgão infectado ou nos linfonodos que drenam estas áreas.","A maioria dos animais infectados desenvolve lesões clinicamente detectáveis.","Os linfonodos podem confinar a infecção por um período de tempo variável antes de um alastramento para outros linfonodos e vísceras.","Nas espécies de hospedeiros resistentes ou nos indivíduos altamente resistentes, os organismos podem se confinar por períodos extensos nos linfonodos.","Os tubérculos, as lesões patológicas clássicas, resultam de uma resposta celular frustrada por parte do hospedeiro e consistem microscopicamente de centros necróticos com um halo de macrófagos e outras células mononucleares."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Sobre as helmintíases gastrintestinais dos ruminantes, analise: I- A oesofagostomose, causada por Oesophagostomum spp., se caracteriza pela formação de nódulos na mucosa intestinal resultantes de um processo inflamatório crônico local causado pela migração de larvas. II- A infecção por Strongyloides papillosus ocorre pela penetração das L3 através da pele íntegra e posterior migração pulmonar antes de atingir o intestino delgado. III- Um fator importante na epidemiologia das parasitoses gastrintestinais de ruminantes é a hipobiose, fenômeno caracterizado pelo retardo ou inibição do desenvolvimento das larvas de quarto estágio inicial (L4 I) dentro do hospedeiro. Está(ão) correta(s):', '["Apenas I.","Apenas II e III.","Apenas I e III.","Apenas III.","I, II e III."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'A eimeriose é uma protozoose entérica de distribuição mundial, que atinge ruminantes submetidos aos mais diferentes sistemas de manejo. Analise: I- É conhecida também como diarreia de sangue ou curso vermelho, causada por protozoários do gênero Eimeria que se multiplicam nas células epiteliais do intestino delgado e grosso; os animais se infectam ao ingerir os oocistos esporulados com a água, a ração ou a pastagem. II- Os sinais clínicos observados são eliminação de fezes aquosas e fétidas, podendo ser sanguinolentas por um a dois dias, desidratação, prostração, perda de apetite e de peso. III- Os adultos comumente não apresentam sinais clínicos, contribuindo para a permanência de animais parasitados no rebanho, constituindo-se nas principais fontes de infecção para os animais jovens. Está(ão) correta(s):', '["Apenas I","Apenas II e III.","Apenas I e III.","Apenas I e II.","I, II e III."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'Sobre a tristeza parasitária bovina e seu controle, a alternativa INCORRETA é:', '["Os bezerros devem ser expostos ao carrapato desde o nascimento, para que desenvolvam imunidade contra os agentes da tristeza parasitária bovina.","Para que o banho de aspersão manual seja eficaz no controle dos carrapatos deve ser aplicado no bovino contido, encharcando todo o seu corpo, com especial cuidado com as áreas mais infestadas, usando em torno de 2 litros por animal.","O período de incubação de Babesia spp. varia de 7 a 10 dias, enquanto o de Anaplasma marginale geralmente é superior a 20 dias.","Trata-se de enfermidade de elevadas morbidade e mortalidade, sobretudo em adultos primo-infectados.","A Babesia bovis é mais patogênica do que a B. bigemina, pois pode desencadear o quadro clínico conhecido como babesiose cerebral."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Em relação à epidemiologia da TPB, analise: I- Nas áreas endêmicas ou de estabilidade enzoótica ocorrem infecções subclínicas, casos clínicos isolados e relativamente baixa mortalidade. II- Nas áreas epidêmicas (instabilidade enzoótica), a maioria do rebanho é suscetível, sendo frequentes os surtos, com elevadas morbidade e mortalidade. III- Nas áreas livres todos os animais são suscetíveis e a doença ocorre quando há entrada acidental de carrapatos em períodos favoráveis, ou quando bovinos dessa região são transferidos para áreas endêmicas. Está(ão) correta(s):', '["Apenas I","Apenas I e II","Apenas III","Apenas II e III.","I, II e III."]'::jsonb, 4),
  ('Toxicologia e Metabolismo', 'A Crotalaria retusa deve ser eliminada das áreas de pastejo dos animais, com o uso de herbicidas ou eliminação manual. Sobre esta planta podemos afirmar que:', '["Contém alcaloides pirrolizidínicos que provocam fibrose hepática e megalocitose (relacionada a um efeito antimitótico).","Contém saponinas litogênicas que induzem a formação de cristais no sistema biliar.","Leva a um quadro clínico-patológico consistente com o de uma insuficiência renal e hepática.","Ocasiona disfunção neurológica devido a polioencefalomalácia e hiperamonemia devido ao fígado lesado não metabolizar a amônia absorvida pelo intestino.","Induz a uma doença do armazenamento, provocando lipidose hepática."]'::jsonb, 0),
  ('Toxicologia e Metabolismo', 'A intoxicação por cobre é caracterizada por duas fases: uma subclínica, durante a qual o Cu se acumula no fígado por semanas ou meses, e outra aguda, decorrente da liberação do cobre acumulado. Em relação a esta enfermidade as afirmativas estão corretas, EXCETO:', '["A ingestão de alimentos contendo níveis de cobre acima dos normais não produz sinais clínicos enquanto o cobre se acumula no fígado. Quando os níveis hepáticos máximos são alcançados, o cobre é liberado na corrente sanguínea, e o animal morre por hemólise intravascular aguda e nefrose hemoglobinúrica.","A intoxicação crônica primária é causada pela ingestão de alimentos contendo altos níveis de Cu. Os bovinos são muito sensíveis à intoxicação, pois apresentam tendência a acumular o cobre no organismo.","Os sinais clínicos aparecem bruscamente, observando-se anorexia, sede, depressão, andar cambaleante, icterícia, hemoglobinúria, fezes líquidas, fétidas e escuras.","As enzimas que indicam dano hepático podem estar elevadas 4-6 semanas antes da crise hemolítica.","A intoxicação secundária inclui a intoxicação crônica fitógena, na qual se produz acúmulo do microelemento em consequência da ingestão de pastagens com baixos níveis de molibdênio; e a intoxicação crônica hepatógena, na qual o Cu se acumula em consequência de lesões hepáticas causadas pela ingestão de plantas tóxicas."]'::jsonb, 1),
  ('Toxicologia e Metabolismo', 'A deficiência de cobre, também denominada hipocuprose, cursa em ruminantes com ampla variedade de manifestações clínicas. Sobre esta enfermidade as afirmações estão corretas, EXCETO:', '["A carência de Cu ocorre geralmente pela ingestão de pastagens com baixa concentração de Cu ou pela ingestão de dietas com cobre normal e ricas em elementos antagonistas como molibdênio e ferro.","Em bovinos a carência de cobre pode causar anemia, osteoporose, hipomielinogênese congênita, alterações da pigmentação dos pelos, diarreia e morte súbita.","A deficiência de cobre pode levar a uma síndrome conhecida como ataxia enzoótica dos cordeiros, com incoordenação dos membros posteriores nas primeiras semanas de vida, podendo em alguns casos produzir paraplegia.","A determinação das concentrações hepáticas de cobre e do conteúdo de cobre nas pastagens constituem indicadores de baixos aportes do elemento e auxiliam no diagnóstico da hipocuprose.","A deficiência de cobre pode ocasionar um processo agudo conhecido como crise hemolítica, com mucosas ictéricas e obstrução dos túbulos renais, que leva o rim a adquirir aspecto entumecido e de coloração bem avermelhada."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Um caprino em fase final de gestação (simples) entrou subitamente em decúbito permanente. A alimentação era composta por forragens nativas e restos de frutas de mercado. Ao exame não havia alterações comportamentais e o animal mantinha o apetite. No exame do sistema nervoso: hiporreflexia nos membros e paralisia flácida. Hemograma sem alterações significativas; urinálise com presença de corpos cetônicos. Com base na anamnese e sintomatologia, quais enfermidades deveriam ser consideradas no diagnóstico presuntivo?', '["Botulismo ou abscesso na região medular.","Toxemia da prenhez e listeriose.","Listeriose e polioencefalomalácia.","Distrofia muscular nutricional e abscesso na região cervical.","Raiva e polioencefalomalácia."]'::jsonb, 0),
  ('Clínica Médica de Grandes Animais', 'Em relação à pericardite traumática as afirmações estão corretas, EXCETO:', '["A retículo-peritonite traumática ocasionalmente pode causar pericardite séptica.","Pericardite fibrinosa pode também ocorrer em bezerros septicêmicos ou bovinos com broncopneumonia bacteriana severa.","Na pericardite traumática a febre nem sempre está presente, porém pulsação e distensão venosa, edema ventral, taquicardia e sons cardíacos abafados bilateralmente são sinais frequentes.","A hiperfibrinogenemia é um achado laboratorial presente apenas na fase inicial da doença.","Na fase aguda e sub-aguda da doença os sons cardíacos, como sopros, atritos e sons de líquido, podem mudar até diariamente."]'::jsonb, 3),
  ('Clínica Médica de Grandes Animais', 'Sobre a acidose ruminal aguda, as afirmações estão corretas, EXCETO:', '["Na acidose aguda, quanto mais se produzir ácido láctico e ácidos graxos voláteis, mais se reduzirá o pH do conteúdo ruminal.","Na acidose o pH ruminal pode cair para 4,5 a 5, momento em que outros micróbios, inclusive o Streptococcus bovis, são destruídos.","O rápido acúmulo de ácido láctico no rúmen puxa osmoticamente água para seu interior, provocando desidratação do animal.","A ruminite química ou ácida danifica a mucosa ruminal e permite transudação plasmática para o interior do rúmen.","Um animal com pH ruminal de 5 ou menos, frequência cardíaca superior a 100 por minuto, desidratação acima de 8%, com distensão ruminal e em decúbito tem indicação de ruminotomia e evacuação do conteúdo."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'Cegueira, opistótono, edema cerebral, herniação cerebelar e necrose do córtex cerebral em bovinos são sinais clínicos e achados patológicos que caracterizam a:', '["Raiva.","Listeriose.","Encefalite por Herpes vírus tipo 5.","Babesiose cerebral.","Polioencefalomalácia."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'A pododermatite contagiosa ovina é uma enfermidade infecciosa e altamente contagiosa do espaço interdigital e tecido córneo que cursa com severa claudicação. Em relação a esta enfermidade, as afirmativas estão corretas, EXCETO:', '["Na forma severa ou patogênica, vários animais do rebanho estão acometidos com claudicação grave e desenvolvimento anormal do tecido córneo. Nos casos avançados pode haver desprendimento entre o estojo córneo e o tecido subjacente, com exsudato necrótico de odor fétido.","A infecção prévia pelo F. necrophorum contribui para o desenvolvimento da doença, propiciando um ambiente favorável para o D. nodosus, pois este agente sozinho não é capaz de estabelecer a enfermidade.","A forma branda ou benigna se caracteriza por eritema local, necrose do tecido interdigital, claudicação transitória e geralmente é autolimitante.","A presença do Dichelobacter nodosus nas pastagens de um ano para o outro é responsável pela perpetuação dos surtos nas propriedades em que a enfermidade é endêmica.","A transmissão ocorre quando um animal infectado é introduzido em um rebanho sadio ou simplesmente através do contato com equipamentos contaminados pelo D. nodosus."]'::jsonb, 3),
  ('Cirurgia de Grandes Animais', 'Após a abertura da cavidade abdominal em equinos com cólica, os procedimentos a serem seguidos em relação às vísceras com distensão gasosa são:', '["Exploração meticulosa dos órgãos cavitários, resolução do problema e miorrafia.","Esvaziamento do gás das vísceras, exploração dos órgãos cavitários, resolução do problema e miorrafia.","Secção dos órgãos com acúmulo de conteúdo sólido, esvaziamento destes órgãos e miorrafia.","Exposição do segmento intestinal acometido, resolução do problema e miorrafia.","Colocação de dreno nas vísceras."]'::jsonb, 1),
  ('Cirurgia de Grandes Animais', 'Na mastite crônica a retirada da glândula mamária pode promover deiscência da ferida por acúmulo de líquidos, o que é evitado com:', '["Hemostasia com cauterização.","Diérese em \"T\".","Lavagem com solução fisiológica.","Síntese empregando o padrão de sutura em \"X\".","Redução de espaço morto subcutâneo."]'::jsonb, 4),
  ('Cirurgia de Grandes Animais', 'Para reduzir a contaminação da musculatura e do subcutâneo durante a ruminotomia, faz-se necessário fixar a camada seromuscular a(ao):', '["Peritônio.","Musculatura.","Pele.","Subcutâneo.","Compressa de algodão."]'::jsonb, 2),
  ('Cirurgia de Grandes Animais', 'Para o tratamento de uma obstrução uretral no "S" peniano em um ruminante, a realização da uretrostomia é o mais indicado. Para minimizar a irritação da pele pela urina, após a cirurgia, o melhor local de incisão é o:', '["Pré-escrotal.","Retro-escrotal.","Pubiano.","Perineal.","Ventral."]'::jsonb, 3),
  ('Cirurgia de Grandes Animais', 'Na herniorrafia incisional em um equino de 350 kg, o padrão de sutura mais indicado para redução do anel herniário é o:', '["Lembert.","Jaquetão.","Cushing.","Cushing-cushing.","Loop-looping."]'::jsonb, 1),
  ('Cirurgia de Grandes Animais', 'A evisceração se caracteriza por:', '["Presença de vísceras no exterior do corpo do animal.","Presença de vísceras no saco herniário.","Ausência de vísceras no espaço subcutâneo.","Coloração das vísceras.","Presença de vísceras no interior da cavidade torácica."]'::jsonb, 0),
  ('Anestesiologia e Farmacologia', 'Qual dos fármacos abaixo seria recomendado para facilitar a confecção da ligadura do cordão espermático de equinos?', '["Acepromazina.","Azaperone.","Morfina.","Cetamina.","Éter gliceril guaiacol."]'::jsonb, 4),
  ('Cirurgia de Grandes Animais', 'Na amputação do membro pélvico de um ovino, deve-se optar pela secção o mais:', '["Distal possível, como forma de facilitar a deambulação após a cirurgia.","Proximal possível, para evitar a deiscência da ferida cirúrgica devida ao contato do coto do membro com o solo.","Distal possível, para evitar a deiscência da ferida cirúrgica.","Proximal possível, para facilitar a secção, pela menor quantidade de músculos.","Distal possível, para evitar a perda dos cascos."]'::jsonb, 1),
  ('Cirurgia de Grandes Animais', 'Na exérese de feridas nas extremidades dos membros de equinos, ocorre hemorragia em pequenos vasos. Visando não retardar a cicatrização, a hemostasia deve ser feita por:', '["Compressão, quando possível, ou por cauterização térmica focal (apenas sobre os vasos sangrantes).","Compressão de troncos vasculares.","Cauterização térmica em toda a área incisada.","Cauterização química.","Cauterização com fenóis."]'::jsonb, 0),
  ('Anestesiologia e Farmacologia', 'Qual fármaco abaixo é utilizado com frequência em bovinos para a realização de procedimentos cirúrgicos, tendo efeito tranquilizante, relaxante muscular de ação central e analgésico?', '["Meperidina.","Cloridrato de xilazina.","Fentanil.","Doxapram.","Isofluorano."]'::jsonb, 1),
  ('Anestesiologia e Farmacologia', 'Na descorna de um Bos taurus indicus deve-se realizar o bloqueio anestésico local:', '["Do nervo pudendo.","Do nervo torácico lateral.","Do nervo óptico.","Infiltrativo circular.","Dos nervos óptico e pudendo."]'::jsonb, 3),
  ('Anestesiologia e Farmacologia', 'Não há informação precisa a respeito do jejum de uma vaca que precisa ser submetida à sedação com xilazina para realizar uma descorna cosmética de urgência. Como você posicionaria o animal para tal procedimento?', '["Decúbito lateral direito.","Decúbito lateral esquerdo.","Decúbito dorsal.","Decúbito esternal esquerdo.","Decúbito esternal direito."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Como proceder no tratamento de uma lesão cutânea com características macroscópicas de habronemose?', '["Retirada cirúrgica da lesão, dermorrafia, biópsia.","Cauterização, tratamento tópico, cultura bacteriana.","Biópsia, retirada cirúrgica da lesão, tratamento parenteral.","Cauterização, tratamento tópico, biópsia.","Retirada cirúrgica da lesão, biópsia, tratamento parenteral/tópico."]'::jsonb, 4),
  ('Cirurgia de Grandes Animais', 'Na preparação de um rufião bovino pela técnica de aderência peniana ventral, qual destes nervos deve ser bloqueado para potencializar o efeito da anestesia infiltrativa local?', '["Axilar.","Torácico lateral (bilateral).","Intercostal.","Torácico lateral (unilateral).","Costal lateral."]'::jsonb, 1),
  ('Cirurgia de Grandes Animais', 'Em casos em que o feto se encontra enfisematoso, o local mais indicado de acesso à cavidade abdominal na cesariana deve ser:', '["Pela região perineal.","Pela linha alba.","Paramamária.","Pela fossa paralombar direita.","Paravertebral."]'::jsonb, 2),
  ('Cirurgia de Grandes Animais', 'Nos casos em que a laparotomia exploratória se faz necessária, havendo suspeita clínica de obstrução no jejuno de bovinos, o acesso à cavidade abdominal deve ser:', '["Paramamária.","Pela fossa paralombar esquerda.","Pela linha alba.","Pela fossa paralombar direita.","Paravertebral."]'::jsonb, 3),
  ('Clínica Médica de Grandes Animais', 'Lesões nodulares e com tecido de granulação irregular, ulceradas e pionecrosadas, localizadas nas extremidades distais de membros e comissura medial palpebral, são características de:', '["Papilomatose.","Dermatomicose.","Pitiose.","Habronemose cutânea.","Hipersensibilidade."]'::jsonb, 3),
  ('Clínica Médica de Grandes Animais', 'Um equino SRD, cinco anos de idade, 350 kg, criado em pastagem nativa, há uma semana apresenta apatia, inapetência, emagrecimento progressivo, depressão acentuada, conjuntivas congestas, escleras ictéricas, ataxia e andar a esmo. Diante desses sinais pode-se suspeitar de:', '["Leucoencefalomalácia.","Encefalomielite equina.","Mieloencefalite por protozoário.","Raiva.","Encefalopatia hepática."]'::jsonb, 4),
  ('Toxicologia e Metabolismo', 'Principal causa de fibrose hepática em equinos criados na região semiárida é...', '["Infecção por Sarcocystis neurona.","Intoxicação crônica pela ingestão de Crotalaria retusa.","Intoxicação por micotoxinas.","Toxicoinfecção por neurotoxinas.","Intoxicação por fumonisina B1."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'Os parâmetros mais utilizados para avaliação das condições clínicas em equinos com dor abdominal aguda são coloração das mucosas, tempo de preenchimento capilar, frequência cardíaca e turgor cutâneo. Estes sinais vitais refletem, respectivamente:', '["Integridade vascular, pressão sistólica, perfusão periférica e hemodinâmica.","Condicionamento físico, perfusão sanguínea periférica, pressão sistólica e hidratação.","Traumatismo local, pressão sistólica, condicionamento físico e hemodinâmica.","Traumatismo local, perfusão sanguínea periférica, condicionamento físico e hidratação.","Integridade vascular, perfusão sanguínea periférica, dor e hidratação."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Sobre a ocorrência de síndrome cólica podemos afirmar que: I- Desidratação e acidose metabólica são verificações comuns. II- Desidratação não se constitui um achado comum. III- Íleo paralítico não é complicação comum em diferentes etiopatogenias de cólicas. IV- Peristalse primária ou secundária podem evoluir a íleo paralítico. V- Ocorre aumento da frequência respiratória e do pulso. Está(ão) correta(s):', '["Apenas I.","Apenas I e II.","Apenas I, IV e V.","Apenas III e V.","Apenas IV e V."]'::jsonb, 2),
  ('Clínica Médica de Grandes Animais', 'Equino Quarto de Milha, seis anos, 450 kg, há três dias com cólica, diarreia intensa e tenesmo retal, taquipneia e narinas dilatadas, taquicardia, aumento da temperatura (39,5º), conjuntivas congestas, retração do globo ocular e TPC>3". Nos achados laboratoriais: VG aumentado, leucocitose com neutrofilia, eosinófilos diminuídos, proteínas séricas elevadas, líquido peritonial levemente escuro. Marque a alternativa com o diagnóstico e algumas complicações secundárias.', '["Cólica tromboembólica, desidratação Grau II, acidose metabólica, endoparasitose.","Cólica espasmódica, desidratação Grau II, acidose metabólica, enterite parasitária.","Cólica por indigestão de carboidratos, desidratação Grau II, acidose metabólica, endotoxemia.","Cólica tromboembólica, desidratação Grau II, acidose metabólica, peritonite.","Cólica espasmódica, desidratação Grau II, acidose metabólica, enterite bacteriana aguda."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Na laminite, quais as principais manifestações sistêmicas observadas na fase inicial?', '["Apatia, apetite exacerbado, queda da pressão arterial e alcalose.","Taquicardia, aumento do tempo de perfusão capilar, queda da pressão arterial e alcalose.","Insuficiência renal aguda, ou glomerulonefrite, consequente à isquemia e/ou utilização de anti-inflamatórios não esteroides e alcalose.","Taquicardia, aumento do tempo de perfusão capilar, acidose metabólica, hipertensão e hemograma característico de estresse.","Taquicardia, aumento do tempo de perfusão capilar, acidose metabólica, deformação do casco."]'::jsonb, 3),
  ('Clínica Médica de Grandes Animais', 'Na fase inicial da laminite, qual dos protocolos abaixo pode ser utilizado como terapêutica básica?', '["Fluidoterapia hidroeletrolítica acidificante, antiálgicos e anti-inflamatórios esteroidais, bloqueadores alfa-adrenérgicos.","Fluidoterapia hidroeletrolítica com lactato de sódio, duchas e pedilúvio frios, anticoagulantes como a heparina, bloqueadores alfa-adrenérgicos como a acepromazina, antiálgicos e anti-inflamatórios não esteroides, curtos períodos de locomoção lenta.","Fluidoterapia hidroeletrolítica acidificante, antiálgicos e anti-inflamatórios não esteroides, curtos períodos de locomoção lenta.","Fluidoterapia hidroeletrolítica com lactato de sódio, duchas e pedilúvio frios, antiálgicos e anti-inflamatórios esteroidais.","Fluidoterapia hidroeletrolítica acidificante, antiálgicos e anti-inflamatórios esteroidais."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'Na determinação das causas de miopatias em equinos podemos incluir como provas diagnósticas:', '["Exame físico, biópsia muscular, concentração de eletrólitos sanguíneos.","Exclusivamente histórico clínico e nutricional, ambiente e confinamento, exame físico.","Biópsia muscular, concentração eletrolítica sanguínea, prova de função renal, hematologia, bioquímica sérica enzimática.","Exclusivamente a avaliação física e hematologia.","A avaliação física, biópsia muscular, concentração de eletrólitos sanguíneos."]'::jsonb, 2),
  ('Clínica Médica de Grandes Animais', 'Constituem importantes fatores predisponentes para a rabdomiólise:', '["Dietas ricas em carboidratos e proteínas em período de inatividade, quando retornados à rotina física.","Súbitas elevações na duração ou intensidade de treinamento após período de inatividade.","Superalimentação com forragem e atividade física, após período de inatividade.","Deficiências nutricionais quando retornados à rotina dos exercícios após período de inatividade.","Atividade física após período de inatividade com dietas compostas por gramíneas."]'::jsonb, 0),
  ('Clínica Médica de Grandes Animais', 'Assinale a alternativa que contém enzimas séricas utilizadas no diagnóstico diferencial entre miopatias e hepatopatias.', '["AST, DLH, GGT.","AST, DLH, GGT, FA.","CPK, AST, DLH, FA.","CPK, AST, DLH.","CPK, DLH, GGT."]'::jsonb, 3),
  ('Clínica Médica de Grandes Animais', 'Qual grupo muscular é lesionado na miopatia fibrótica?', '["O músculo semitendinoso, com aderências ou sinéquias entre o semimembranoso e bíceps femoral.","O músculo semitendinoso.","O músculo semimembranoso.","O músculo semimembranoso com aderências entre o semitendinoso e bíceps femoral.","O músculo semitendinoso, com aderências ou sinéquias apenas com o semimembranoso."]'::jsonb, 0),
  ('Cirurgia de Grandes Animais', 'Patologias como neoplasias, pitiose e paralisia intratável do pênis em equinos são indicativas de amputação peniana. Sobre o procedimento cirúrgico é INCORRETO afirmar que:', '["A aplicação de um torniquete na base do pênis facilita a cirurgia por propiciar menor sangramento.","O formato da incisão para exposição da uretra deve ser triangular com o ápice do triângulo voltado caudalmente.","A incisão inicial é feita no aspecto ventral do pênis com finalidade de exposição da uretra.","A amputação proximal é facilitada pela maior facilidade de dissecação do prepúcio.","Após a secção do corpo peniano, aplicam-se suturas na túnica albugínea por sobre os corpos cavernosos com finalidade de ocluí-los."]'::jsonb, 3),
  ('Cirurgia de Grandes Animais', 'O acesso cirúrgico mais indicado na ruminotomia, dilatação e torção do ceco em ruminantes e cesariana em equinos, são, respectivamente:', '["Mediana ventral retroumbilical, paralombar direita e paralombar esquerda.","Paralombar esquerda, paralombar direita e mediana ventral retroumbilical.","Paralombar esquerda, mediana ventral pré-retroumbilical e mediana ventral retroumbilical.","Paralombar direita, paralombar direita e paramediana pré-umbilical.","Paralombar direita, paramediana retroumbilical e mediana ventral retroumbilical."]'::jsonb, 1),
  ('Cirurgia de Grandes Animais', 'Em qual das afecções de bovinos abaixo NÃO é feita indicação para a amputação digital?', '["Fratura intratável da segunda falange.","Artrite séptica interfalangeana não responsiva à antibioticoterapia.","Artrite séptica metatarsofalangeana ou metacarpofalangeana.","Luxação interfalangeana proximal.","Osteomielite das falanges distal e média."]'::jsonb, 3),
  ('Cirurgia de Grandes Animais', 'Patologia caracterizada por impossibilidade de flexão do membro pélvico durante o caminhar, que acomete bovinos e equinos, proporcionando "travamento" do membro, desgaste da(s) pinça(s) do(s) casco(s) do membro afetado, de ocorrência intermitente podendo tornar-se frequente. Assinale a alternativa que contém o nome da patologia e o tratamento mais indicado:', '["Luxação tíbio-társica e artrodese.","Fixação dorsal da patela e desmotomia patelar medial.","Fixação coxofemoral e amputação da cabeça do fêmur.","Fixação medial da patela e tenotomia do extensor digital lateral.","Luxação tíbio-társica e neurectomia digital."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Carlos Chagas, médico sanitarista e pesquisador, ao assumir a direção do recém-criado Departamento Nacional de Saúde Pública (DNSP) em 1920, reorganizou os serviços de saúde. Sobre as atribuições do DNSP, assinale a afirmativa correta.', '["Estabelecer uma política de vacinação infantil.","Criar o Programa Nacional de Imunizações no Brasil.","Instituir, no âmbito federal, a Fundação Oswaldo Cruz.","Fornecer e fiscalizar o preparo de soros e vacinas.","Suprimir o controle sanitário dos portos marítimos e fluviais."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'A Reforma Sanitária Brasileira, gestada desde a década de 1970 e consolidada na década de 1980, desenvolveu-se em meio a disputas entre diferentes atores sociais, políticos e econômicos. Considerando os atores envolvidos nesse processo de reforma, cabe destacar o papel desempenhado', '["pelas grandes instituições hospitalares privadas, que assumiram a liderança política do processo de unificação dos sistemas de saúde existentes.","por setores empresariais e financeiros, que defenderam o financiamento integral do novo sistema público de saúde pelo Estado.","por movimentos sociais, que articularam propostas voltadas à universalização do acesso e à democratização das políticas públicas de saúde.","por corporações médicas tradicionais, que se colocaram à frente da formulação de políticas de descentralização e regionalização da saúde.","por setores do regime militar, que buscaram garantir a expansão dos serviços públicos de saúde sem romper com a lógica do mercado."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a organização do Sistema Único de Saúde - SUS, o planejamento da saúde, a assistência à saúde e a articulação interfederativa, considerando o Decreto nº 7.508/2011 que regulamentou a Lei nº 8.080/1990, assinale a afirmativa correta.', '["As Regiões de Saúde serão referência para as transferências de recursos entre os entes federativos.","As portas de entrada às ações e aos serviços de saúde nas Redes de Atenção à Saúde serão a atenção primária e a atenção de urgência e emergência.","Os serviços ambulatoriais especializados serão considerados como Portas de Entrada, em virtude da densidade tecnológica para a Rede de Saúde.","As Redes de Atenção à Saúde estarão compreendidas no âmbito de uma Região de Saúde, em consonância com as diretrizes pactuadas entre as secretarias municipais.","O Ministério da Educação e os Hospitais Universitários vinculados a ele terão a competência de dispor sobre a RENAME, assim como sobre os Protocolos Clínicos e Diretrizes Terapêuticas."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'Um paciente realizou uma biópsia de cordas vocais em um hospital rural de pequeno porte. Quando o resultado mostrou se tratar de um carcinoma epidermoide de laringe, o paciente foi regulado para tratamento com quimio e radioterapia no CACON mais próximo. Assinale a opção que apresenta o princípio do SUS que melhor embasa esse encaminhamento e tratamento.', '["Equidade.","Universalidade.","Integralidade.","Hierarquização.","Justiça Social."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A Lei nº 8.142/1990 estabelece condições para que os Municípios recebam recursos do Fundo Nacional de Saúde (FNS), como formar Conselhos de Saúde, elaborar planos de saúde e produzir relatórios de gestão. Assinale a opção que indica corretamente o que ocorre caso estes requisitos não sejam atendidos.', '["O Município continua recebendo normalmente os repasses do FNS, mas com restrição para utilizá-los em despesas de custeio.","O Município passa a receber os repasses em caráter parcial, com valores reduzidos proporcionalmente ao descumprimento das exigências legais.","Os recursos deixam de ser transferidos diretamente ao Município e passam a ser administrados pela esfera de governo imediatamente superior.","O Município permanece recebendo os repasses, mas fica obrigado a devolver anualmente os valores aplicados sem comprovação em relatórios de gestão.","O Município tem suspensas apenas as transferências estaduais, mas mantém os recursos federais normalmente, sob fiscalização da União."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'Rede de Atenção à Saúde (RAS) promove a integração vertical (entre diferentes níveis) e a integração horizontal (entre serviços similares). Assinale a opção que exemplifica um caso de integração vertical.', '["Laboratórios de análises clínicas de municípios vizinhos organizam uma central única de processamento de exames laboratoriais.","Três Centros de Atenção Psicossocial de uma região pactuam ações conjuntas para manejo de crises e internação em leitos de saúde mental.","Dois hospitais gerais firmam um convênio para otimizar o uso de seus centros cirúrgicos e reduzir a fila de cirurgias eletivas.","Uma Unidade Básica de Saúde encaminha um paciente para atendimento especializado e posterior tratamento em unidade de alta complexidade.","Duas Unidades Básicas de Saúde de bairros vizinhos compartilham uma equipe de Saúde Bucal para ampliar o atendimento odontológico."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'Com relação às Redes de Atenção à Saúde (RAS), avalie: ( ) Um dos atributos das RAS é a adscrição de clientela, ou seja, a definição de uma população em território específico para cada ponto de atenção. ( ) Um dos objetivos das RAS é garantir a referência e a contrarreferência adequadas entre os serviços, assegurando continuidade do cuidado. ( ) A Atenção Primária à Saúde ocupa posição periférica na rede, que tem como enfoque o atendimento em serviços especializados ou hospitalares. As afirmativas são, respectivamente,', '["F – V – F.","F – V – V.","V – F – F.","V – V – F.","F – F – V."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'As Equipes Consultório na Rua (ECR) são o braço do SUS voltado para o atendimento às populações em situação de rua. Para ser atendido por uma ECR, é necessário que o indivíduo', '["comprove nacionalidade brasileira no momento do atendimento.","busque ativamente o atendimento junto à unidade de saúde de referência.","possua encaminhamento formal de unidade de saúde da atenção primária.","seja identificado como em situação de rua por uma abordagem ativa das equipes.","esteja previamente cadastrado no sistema governamental para o acesso a programas sociais."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a Portaria nº 2.803/2013, que redefine e amplia o Processo Transexualizador no SUS, analise as diretrizes de assistência: I. Garantir a integralidade da atenção, centralizando a meta terapêutica nas cirurgias de transgenitalização e demais intervenções somáticas. II. Providenciar que o atendimento seja sempre realizado por equipes interdisciplinares e multiprofissionais. III. Implementar a integração com as ações e serviços, tendo como entrada a Atenção Básica, incluindo acolhimento e humanização livre de discriminação. As afirmativas são, na ordem apresentada,', '["F – V – V.","V – V – V","F – V – F.","V – F – V.","F – F – V."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'A Estratégia Saúde da Família (ESF) tem entre seus atributos a longitudinalidade. Assinale a opção que exemplifica corretamente esse atributo.', '["Realização de ações educativas em grupos comunitários para promoção de hábitos saudáveis.","Integração de diferentes níveis de atenção para garantir acesso a exames e cirurgias de alta complexidade.","Encaminhamento imediato de casos agudos para o atendimento especializado, visando rápida resolução.","Planejamento de ações com base em indicadores epidemiológicos locais, priorizando grupos de risco.","Acompanhamento contínuo de um paciente com hipertensão arterial por uma mesma equipe de saúde ao longo dos anos."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'A Portaria nº 2.436/2017 estabelece as responsabilidades das esferas do governo na Política Nacional de Atenção Básica (PNAB). Assinale a opção que exemplifica um caso em que uma dessas responsabilidades é violada.', '["A União direcionou parte maior de seus repasses financeiros relativos à cobertura de Atenção Básica para municípios com maior densidade populacional.","Um Estado estabeleceu metas de expansão da cobertura de serviços, priorizando inicialmente regiões metropolitanas e, em etapas posteriores, áreas rurais.","Equipes de Saúde utilizaram os sistemas oficiais de informação da Atenção Básica para monitorar atendimentos, analisar indicadores e planejar intervenções.","Um Município ampliou a infraestrutura de suas UBS, criando consultórios adicionais e adaptando gradualmente os espaços para atender melhor à população.","Conselhos Municipais de Saúde organizaram encontros periódicos com representantes da comunidade para discutir prioridades locais."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'Sobre as equipes que integram a Estratégia Saúde da Família (ESF), no contexto da PNAB, assinale a afirmativa correta.', '["É obrigatória a participação de um profissional de saúde bucal.","Em áreas consideradas de risco, é aceitável a cobertura pela equipe de ESF de até 75% do território.","Não há necessidade das categorias de médicos e enfermeiros serem especialistas em medicina de família e comunidade e saúde da família, respectivamente.","Para a equipe de ESF, há a obrigatoriedade de carga horária de 10 horas semanais para todos os profissionais que a compõem.","É de responsabilidade de cada profissional a distribuição da carga horária, garantindo 100% de cobertura."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A Política Nacional de Educação Permanente em Saúde (PNEPS) busca fortalecer a integração entre os processos formativos dos profissionais de saúde e os diversos aspectos de sua atuação. Assinale a opção que exemplifica uma ação compatível com os objetivos da PNEPS.', '["A equipe gestora de um hospital promove capacitações técnicas com foco em atualização de procedimentos clínicos previamente definidos em planos anuais.","Profissionais de uma unidade básica de saúde organizam encontros periódicos para elaborar estratégias que qualifiquem o cuidado a partir da realidade local.","Uma instituição oferece cursos presenciais com foco em habilidades técnicas voltadas ao atendimento em unidades de média complexidade.","O departamento de ensino de uma Secretaria de Saúde realiza oficinas sobre gestão de processos administrativos e uso de ferramentas digitais.","Uma empresa contratada ministra treinamentos sobre protocolos assistenciais com base em diretrizes nacionais de boas práticas clínicas."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Em um hospital público, os gestores e profissionais percebem que os longos tempos de espera no pronto-socorro comprometem a qualidade do atendimento. Para resolver o problema, reorganizam a escala de trabalho da equipe e implantam acolhimento com classificação de risco. Assinale a opção que indica o princípio da Política Nacional de Humanização exemplificado pela iniciativa dos gestores.', '["Protagonismo.","Transversalidade.","Corresponsabilidade.","Autonomia dos sujeitos e coletivos.","Indissociabilidade entre ação e gestão."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Segundo a Portaria nº 1.378/2013, do GM/MS, a Agência Nacional de Vigilância Sanitária deve', '["coordenar o Programa Nacional de Imunizações, incluindo a definição das vacinas componentes do calendário nacional.","regular, controlar e fiscalizar os procedimentos, os produtos, as substâncias e os serviços de saúde e de interesse para a saúde.","coordenar a preparação e a resposta das ações de vigilância em saúde nas emergências de Saúde Pública.","prover os insumos de prevenção, diagnóstico e tratamento de doenças sexualmente transmissíveis.","prover os insumos destinados ao controle de doenças transmitidas por vetores."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Com base nos tipos de ação previstos na Política Nacional de Vigilância em Saúde (PNVS), assinale a opção que apresenta uma situação que NÃO se enquadra no escopo dessa política.', '["Inspeção sanitária em estabelecimentos que produzem alimentos e medicamentos.","Realização de campanhas de vacinação para prevenir surtos de doenças transmissíveis.","Acompanhamento de condições de saúde relacionadas ao ambiente de trabalho.","Monitoramento da qualidade da água e do ar em áreas urbanas e rurais.","Vistoria de equipamentos hospitalares com foco em controle de custos."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Relacione os princípios clássicos da bioética (1. Autonomia, 2. Justiça, 3. Não-maleficência, 4. Beneficência) a violações: ( ) procedimento cirúrgico invasivo sem informar riscos e alternativas; ( ) medicamento com toxicidade conhecida e superior ao benefício esperado; ( ) pacientes com convênio priorizados sobre pacientes do SUS; ( ) manter tratamento agressivo e doloroso a paciente terminal sem benefício. Assinale a relação correta, na ordem apresentada.', '["1, 3, 2 e 4.","1, 4, 2 e 3.","4, 2, 3 e 1.","2, 4, 3 e 1.","4, 3, 2 e 1."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'No contexto do Programa Nacional de Segurança do Paciente (PNSP), assinale a opção que indica uma ação obrigatória para os serviços de saúde.', '["Garantir visitas irrestritas em unidades de terapia intensiva.","Priorizar intervenções farmacológicas off-label, sem notificação.","Resguardar os processos decisórios da participação de pacientes e acompanhantes.","Implementar Núcleos de Segurança do Paciente nos estabelecimentos de saúde.","Usar terminologias médicas em linguagem técnica nos prontuários dos pacientes."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'A Norma Regulamentadora nº 32 (NR-32) estabeleceu diretrizes de segurança e saúde no trabalho no âmbito dos serviços de saúde, incluindo exposição a riscos químicos e biológicos. Assinale a opção que indica um risco biológico.', '["Inalação de gases anestésicos em centro cirúrgico.","Exposição a vapores de formaldeído em sala de anatomia.","Inalação de óxido nitroso em procedimentos odontológicos.","Contato com sangue contaminado durante a coleta de amostras laboratoriais.","Manipulação de glutaraldeído para desinfecção de equipamentos hospitalares."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'Durante o acompanhamento de um idoso com múltiplas condições crônicas, o médico ajustou a medicação, a nutricionista elaborou uma nova dieta e o fisioterapeuta prescreveu exercícios. O paciente saiu da unidade sem compreender como as atividades prescritas tratam seus sintomas. Na situação exposta, trata-se de um problema de', '["fragmentação do cuidado multiprofissional.","comunicação deficiente entre os profissionais.","sobrecarga de trabalho dos profissionais de saúde.","hierarquização entre as profissões da equipe de saúde.","precarização dos vínculos de trabalho na atenção primária."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Eutanásia, segundo a Resolução Normativa nº 37/2018 do CONCEA, é o modo humanitário de induzir a morte do animal, sem dor e com mínimo estresse, de maneira controlada e assistida. A eutanásia animal é indicada', '["quando o estado de saúde ou o bem-estar do animal impossibilite o tratamento ou socorro.","quando o proprietário/tutor do animal solicita e autoriza o médico-veterinário a realizar o procedimento.","quando o tratamento do animal representar custos compatíveis com a atividade produtiva a que o animal se destina.","para fins didáticos, científicos e testes de produtos de uso humano, como medicamentos e cosméticos em geral.","para o bem do próprio indivíduo, em casos de dor ou sofrimento que podem ser mitigados de imediato com analgésicos, sedativos ou outros métodos."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a eutanásia animal, analise: I. É um procedimento clínico cuja implementação compete privativamente ao médico-veterinário. II. É um modo humanitário de induzir a morte do animal, sem dor e com mínimo estresse. III. Para fins didáticos e científicos, no Brasil, é normatizada pelo CONCEA. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a Lei de Crimes Ambientais (Lei nº 9.605/1998, alterada pela Lei nº 14.064/2020), analise: I. É crime matar, perseguir, caçar, apanhar, utilizar espécimes da fauna silvestre, exceto com a devida permissão, licença ou autorização da autoridade competente. II. É crime praticar ato de abuso, maus-tratos, ferir ou mutilar animais silvestres, domésticos ou domesticados, com pena de detenção e multa. III. Quando se tratar de cão ou gato, a pena para maus-tratos é aumentada, além da aplicação de multa e proibição da guarda. Está correto o que se afirma em', '["II, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a Lei nº 5.517/1968, que dispõe sobre o exercício da profissão de Médico-Veterinário, analise: I. É competência privativa a regência de cadeiras ou disciplinas específicas dessa área, bem como a direção das respectivas seções e laboratórios. II. É competência privativa a organização de congressos, comissões, seminários e outras reuniões destinadas ao estudo da Medicina Veterinária. III. É competência privativa a inspeção e fiscalização sanitária, higiênica e tecnológica dos estabelecimentos de produção, manipulação, armazenagem e comercialização de produtos de origem animal. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a Lei nº 11.794/2008 (Lei Arouca), que regulamenta o uso científico de animais no Brasil: ( ) Estabelece os critérios para a criação e utilização de animais em atividades de ensino e pesquisa científica. ( ) A utilização de animais em atividades educacionais fica restrita a estabelecimentos de ensino superior e de educação profissional técnica de nível médio da área biomédica. ( ) O disposto nesta Lei aplica-se a todas as espécies de animais do Filo Chordata. As afirmativas são, respectivamente,', '["V – V – V.","F – V – F.","V – V – F.","V – F – V.","F – V – V."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A Resolução nº 1.649/2025 do CFMV orienta médicos-veterinários diante das transformações do ambiente digital. ( ) Os profissionais respondem eticamente pela divulgação de matérias enquanto ofertantes diretos dos serviços, responsáveis técnicos, proprietários ou diretores de estabelecimentos. ( ) São eticamente responsáveis por todo o conteúdo que postam, repostam e compartilham em redes sociais, exceto materiais de terceiros e/ou pacientes. ( ) Na publicidade de estabelecimentos deve constar o nome e número de inscrição do responsável técnico. As afirmativas são, respectivamente,', '["V – F – V.","F – V – V.","V – V – F.","V – F – F.","V – V – V."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'A propaganda e publicidade na Medicina Veterinária são normatizadas pela Resolução CFMV nº 1.649/2025. ( ) É permitido veicular publicidade de produtos, logomarcas e logotipos de terceiros em documentos produzidos tecnicamente. ( ) É vedado divulgar ou associar os serviços a preços abaixo do custo de mercado com objetivo de eliminar concorrentes. ( ) É permitido participar de propaganda de medicamento, insumo, equipamento ou serviço que garantam resultados. As afirmativas são, respectivamente,', '["V – V – F.","F – V – F.","V – F – V.","V – V – V.","F – F – F."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Sobre as Diretrizes Gerais de Responsabilidade Técnica em Programas, Campanhas e Mutirões de esterilização cirúrgica de caninos e felinos (Resolução CFMV nº 1596/2024): ( ) Os procedimentos pré, trans e pós-operatórios devem priorizar a sanidade, segurança e bem-estar dos animais, sendo secundária a quantidade de intervenções. ( ) São ações realizadas preferencial, mas não exclusivamente, por entidades de utilidade pública, faculdades de Medicina Veterinária e órgãos públicos. ( ) Devem ter por base a educação em saúde, bem-estar animal e guarda responsável, e não apenas o fluxo de esterilizações. As afirmativas são, respectivamente,', '["F – V – V.","F – V – F.","V – F – V.","V – V – V.","F – F – F."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'A Resolução nº 1.653/2025 do CFMV padroniza termos e regras sobre conteúdo e entrega de cópias de prontuários médico-veterinários. ( ) Substitui "proprietário" ou "tutor" por "responsável pelo animal". ( ) Estabelece prazo de 5 dias úteis para entrega de cópia do prontuário, contados do protocolo do pedido. ( ) A entrega pode ser prorrogada para até 15 dias, mediante justificativa. As afirmativas são, respectivamente,', '["F – V – V.","V – V – F.","V – V – V.","F – V – F.","V – F – V."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Sobre o SinPatinhas, Sistema do Cadastro Nacional de Animais Domésticos lançado em 2025: I. Integra o ProPatinhas, cujo objetivo é tirar os animais da invisibilidade, reunindo dados para políticas públicas de bem-estar animal. II. Podem se cadastrar tutores, médicos-veterinários, clínicas, hospitais, ONGs e protetores independentes; somente médicos-veterinários podem registrar procedimentos como vacinação e microchipagem. III. Os animais registrados terão carteirinha digital com QR Code, para identificação e devolução em caso de perda. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'Sobre a Lei nº 14.228/2021, que dispõe sobre a eliminação de cães e gatos pelos órgãos de controle de zoonoses, assinale a afirmativa INCORRETA.', '["É vedada a eliminação da vida de cães e gatos pelos órgãos de controle de zoonoses, exceto a eutanásia em casos de doenças graves ou infectocontagiosas incuráveis que coloquem em risco a saúde humana e a de outros animais.","A eutanásia deverá ser justificada por laudo do responsável técnico pelos órgãos e estabelecimentos, precedido, quando for o caso, de exame laboratorial.","As entidades de proteção animal devem ter acesso irrestrito à documentação que comprove a legalidade da eutanásia.","O animal com doença infectocontagiosa incurável que caracterize risco à saúde pública poderá ser disponibilizado para resgate por entidade de proteção dos animais.","O descumprimento dessa Lei sujeita o infrator às penalidades previstas na Lei de Crimes Ambientais (Lei nº 9.605/1998)."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'Sobre o exercício das atividades de assistência médico-veterinária envolvendo produtos para uso em animais (Resolução CFMV nº 1318/2020), analise: I. O funcionamento dos estabelecimentos requer registro no Sistema CFMV/CRMVs e homologação da anotação de responsabilidade técnica do Médico-Veterinário. II. A administração do estabelecimento poderá, mediante justificativa, desautorizar ou desconsiderar as orientações técnicas do responsável técnico. III. Medicamentos, insumos ou correlatos para uso humano destinam-se exclusivamente ao atendimento dos respectivos pacientes, vedado o fornecimento ao responsável pelo animal. Está correto o que se afirma em', '["III, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A Resolução nº 1275/2019 do CFMV conceitua e estabelece condições para o funcionamento de estabelecimentos médico-veterinários de atendimento a animais de estimação de pequeno porte. Analise: I. São considerados animais de pequeno porte todas as raças de cães e gatos, pequenos mamíferos, aves e répteis criados como animais de companhia. II. Procedimentos ambulatoriais são intervenções de baixa complexidade, que não necessitam de anestesia geral, podendo ser sob contenção ou sedação (ex: suturas superficiais, anestesia local, curativos, fluidoterapia, coleta de material). III. Estabelecimentos médico-veterinários são as unidades onde são realizados quaisquer tipos de intervenção médico-veterinária. Está correto o que se afirma em', '["II, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'De acordo com a Resolução nº 1275/2019 do CFMV, assinale a afirmativa correta.', '["Ambulatórios Veterinários atendem animais do público externo para exame clínico, procedimentos ambulatoriais e vacinação, sendo vedada anestesia geral e/ou procedimentos cirúrgicos e internação.","Consultórios Veterinários destinam-se ao ato básico de consulta clínica, procedimentos ambulatoriais e vacinação, sendo permitida a realização de anestesia geral e procedimentos cirúrgicos.","Os consultórios de propriedade de médico-veterinário, quando caracterizados como pessoa física, estão sujeitos a taxa de inscrição e anuidade, obrigados ao registro no CRMV.","As Clínicas Veterinárias destinam-se ao atendimento de animais sob responsabilidade técnica, supervisão e presença de médico-veterinário durante todo o período de atendimento e/ou internação.","Hospitais Veterinários destinam-se ao atendimento de animais em período integral, sob responsabilidade técnica, supervisão e presença permanente (24 horas) de médico-veterinário."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'A Resolução nº 1565/2023 do CFMV estabelece procedimentos para a Suspensão Cautelar do Exercício Profissional. Analise: I. Poderá ser aplicada quando o médico-veterinário realizar procedimentos, tratamentos e/ou prescrições vedados por critérios éticos. II. Poderá ser aplicada quando praticar ou acobertar o exercício ilegal da profissão. III. Poderá ser aplicada quando praticar atos de crueldade e abuso aos animais, no exercício da profissão ou fora deste. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre deveres do Médico-Veterinário, de acordo com o Código de Ética, analise: I. Fornecer informações de interesse da saúde pública e de ordem econômica às autoridades competentes nos casos de enfermidades de notificação obrigatória. II. Não informar a abrangência, limites e riscos de suas prescrições e ações profissionais. III. Realizar a eutanásia nos casos devidamente justificados, observando princípios básicos de saúde pública, legislação de proteção aos animais e normas do CFMV. Está correto o que se afirma em', '["II, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'Sobre deveres do Médico-Veterinário, de acordo com o Código de Ética, analise: I. Combater o exercício ilegal da Medicina Veterinária denunciando toda violação às funções específicas que a ela compreende. II. Comunicar ao CRMV, com discrição e de forma fundamentada, qualquer fato que possa caracterizar infração ao código e às normas e leis que regem o exercício da profissão. III. Comunicar aos órgãos competentes e ao CRMV as falhas nos regulamentos, procedimentos e normas das instituições em que trabalhe, sempre que representar riscos à saúde humana ou animal. Está correto o que se afirma em', '["III, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre os direitos do Médico-Veterinário, de acordo com o Código de Ética, analise: I. Exercer a Medicina Veterinária sem ser discriminado por questões de religião, raça, sexo, nacionalidade, cor, orientação sexual, idade, condição social, opinião política ou de qualquer outra natureza. II. Apontar falhas nos regulamentos, procedimentos e normas das instituições em que trabalhe, bem como em programas, normas, portarias, decretos e leis, comunicando o fato aos órgãos competentes e ao CRMV. III. Receber desagravo público, quando solicitar ao CRMV, se ofendido no exercício de sua profissão. Está correto o que se afirma em', '["II, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'Sobre procedimentos vedados ao Médico-Veterinário, de acordo com o Código de Ética, analise: I. Afastar-se de suas atividades profissionais sem deixar outro colega para substituí-lo em atividades essenciais e/ou exclusivas que causem riscos diretos ou indiretos à saúde animal ou humana. II. Receitar, ou atestar de forma ilegível ou assinar sem preenchimento prévio receituário, laudos, atestados, certificados, guias de trânsito e outros. III. Comunicar as condições de trabalho que colocam em risco a saúde ou integridade física dos membros da equipe. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Sobre procedimentos vedados ao Médico-Veterinário, de acordo com o Código de Ética, analise: I. Fornecer ao cliente relatórios, prontuários, atestados e certificados, bem como deixar de dar explicações necessárias à sua compreensão. II. Alterar prescrição ou tratamento determinado por outro médico-veterinário, salvo em situação de indispensável conveniência para o paciente, comunicando imediatamente o fato ao profissional responsável. III. Deixar de encaminhar de volta ao Médico-Veterinário o paciente enviado para procedimento especializado, e/ou não fornecer as devidas informações sobre o ocorrido. Está correto o que se afirma em', '["II, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 3),
  ('Produção Animal e Zootecnia', 'O manejo reprodutivo de marrãs de reposição inicia-se com a chegada desses animais na propriedade. Sobre a indução da puberdade em marrãs, assinale a opção que caracteriza, corretamente, essa prática de manejo.', '["Consiste na exposição das fêmeas suínas jovens a machos adultos (acima de 10 meses) duas vezes ao dia, por 10 a 15 minutos, permitindo contato focinho a focinho entre ambos os animais.","Consiste em protocolos hormonais por meio de implantes intravaginais com progesterona e medicamentos injetáveis contendo prostaglandinas e estradiol, em ciclos adaptados para fêmeas jovens.","Consiste no estímulo físico do macho na cobertura das fêmeas a partir de 100 dias de idade, usando machos com 5 a 6 meses de idade por serem menores e mais leves.","Consiste na exposição de fêmeas caprinas jovens a bodes adultos (acima de 12 meses) duas vezes ao dia, por 15 minutos, permitindo contato com feromônios via sistema olfatório.","Consiste em uma associação entre manejo e hormônios exógenos, expondo as fêmeas suínas jovens à presença do macho adulto associado a protocolos hormonais, com indução do cio e prenhez 30 dias após o início da prática."]'::jsonb, 0),
  ('Produção Animal e Zootecnia', 'A produção de genética de suínos é organizada em granjas núcleo e multiplicadoras. Sobre a composição genética e taxas de reposição desses rebanhos, analise: I. As granjas núcleo são responsáveis pelo melhoramento genético das raças puras e linhagens sintéticas, usando seleção intensiva das características economicamente importantes. II. A taxa de reposição anual recomendável para as granjas núcleo é de 100 a 200% para machos e de 70 a 100% para fêmeas, evitando-se a consanguinidade. III. As granjas multiplicadoras são responsáveis pela produção de matrizes, principalmente fêmeas F1 e machos, a partir de animais de raças puras ou linhagens sintéticas vindos das granjas núcleo. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Produção Animal e Zootecnia', 'O manejo correto da matriz em lactação e de leitões recém-nascidos envolve a manutenção desses animais em sua zona de termoneutralidade. Assinale a opção que apresenta, corretamente, os comportamentos esperados ao submeter leitões com cinco dias de idade a 32°C e a matriz lactente a 20°C.', '["Leitões: tremendo e amontoados. / Matriz: descansando confortavelmente.","Leitões: descansando confortavelmente. / Matriz: inquieta e ofegante.","Leitões: descansando confortavelmente. / Matriz: descansando confortavelmente.","Leitões: ofegantes e espalhados na baia. / Matriz: inquieta e ofegante.","Leitões: descansando confortavelmente. / Matriz: letárgica e tremendo."]'::jsonb, 1),
  ('Produção Animal e Zootecnia', 'A composição dos alimentos destinados aos ruminantes tem grande importância nutricional e sanitária, pois determinados tipos de alimentos podem veicular doenças. Assinale a opção que indica o insumo proibido de ser fornecido a bovinos no Brasil.', '["Ovo em pó.","Farinha de pena hidrolisada.","Lactoalbumina.","Cana de açúcar integral.","Farelo de cevada."]'::jsonb, 1),
  ('Produção Animal e Zootecnia', 'De acordo com as boas práticas na ordenha de vacas leiteiras, assinale a opção que indica, corretamente, a ordem da linha de ordenha.', '["É definida pela idade da vaca e pelo número de partos: vacas mais velhas e pluríparas são ordenhadas primeiro e, em seguida, as primíparas.","É definida pela produtividade: vacas com maior potencial leiteiro são ordenhadas primeiro e, sucessivamente, de acordo com a produtividade.","É definida pelo tempo de lactação: vacas finalizando a lactação são ordenhadas primeiro em relação às que estão entrando em lactação.","É definida tradicionalmente pela ocorrência ou não de mastite: iniciando com vacas primíparas que nunca tiveram mastite e finalizando com as que apresentam mastite clínica.","É definida pela condição sanitária do animal: vacas com mastite ou problemas de casco são ordenhadas primeiro e, por último, as vacas sem nenhum problema sanitário."]'::jsonb, 3),
  ('Saúde Pública e Legislação Veterinária', 'A Influenza Aviária de Alta Patogenicidade (IAAP) e a Doença de Newcastle (DNC) motivaram a criação de um plano de contingência que define ações nas áreas de risco epidemiológico (foco, área perifocal, de vigilância e proteção). Sobre as ações corretas na área perifocal, analise: I. Investigação em todas as propriedades com aves, a cada 3 dias, com registro de inspeções e ocorrências. II. Depopulação imediata de todas as aves existentes na unidade epidemiológica, de preferência no próprio local. III. Proibição de movimentação e retirada de aves da propriedade dentro da área, exceto as destinadas a abate sanitário em matadouro situado dentro da área ou próximo. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'O Código Sanitário para os Animais Terrestres da OMSA define vacinação de emergência como programa de vacinação aplicado como resposta imediata a um foco ou ao aumento de risco de introdução ou surgimento de uma doença. Sobre a vacinação contra Influenza aviária no Brasil, assinale a afirmativa correta.', '["Devem ser vacinadas todas as aves da área de foco.","A vacina só pode ser realizada em aves da área de vigilância e foco.","A vacina é permitida somente em galiformes e ratitas da área perifocal.","A utilização de vacina contra a influenza aviária na área de foco é proibida no Brasil.","O controle dos lotes vacinados deve se dar pela colocação de aves sentinelas vacinadas."]'::jsonb, 3),
  ('Produção Animal e Zootecnia', 'A Portaria nº 1.179/2024 da SDA/MAPA uniformiza a nomenclatura de ovos em natureza e de produtos de ovos. Assinale a opção que apresenta, corretamente, a definição de ovo liofilizado.', '["Produto resultante da desidratação do ovo integral pasteurizado.","Produto resultante da desidratação da clara realizada em etapa anterior ou posterior à pasteurização.","Ovo submetido à secagem por meio do emprego de frio e vácuo, no qual a água é retirada do produto por sublimação.","Ovo desprovido de casca que conserva as mesmas proporções de clara e gema de um ovo em natureza, destinado à pasteurização.","Produto resultante do tratamento térmico do ovo por cozimento, seguido de descasque, adicionado de salmoura ácida ou outros ingredientes."]'::jsonb, 2),
  ('Produção Animal e Zootecnia', 'Uma das etapas do beneficiamento de ovos é a lavagem, que garante a manutenção da higiene e é obrigatória para ovos destinados à comercialização. Analise: I. A lavagem deve ser realizada por meios mecânicos, com procedimentos que impeçam a penetração microbiana no interior do ovo. II. A lavagem de ovos sujos e trincados é obrigatória. III. A operação deve ser contínua e completada o mais rápido possível, não se permitindo equipamentos de lavagem por imersão. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A infecção por Salmonella spp. é uma grande preocupação na avicultura nacional, com controle e monitoramento regulamentados pela Instrução Normativa nº 20/2016. Analise: I. Devem ser adotadas medidas de controle específicas para Salmonella Typhimurium e Salmonella Enteritidis, por serem patógenos de grande relevância em Saúde Pública. II. Devem ser adotadas medidas específicas para Salmonella Pullorum e Salmonella Gallinarum, por serem patógenos de grande relevância em Saúde Pública. III. Devem ser adotados o monitoramento e controle de Salmonella spp. nos estabelecimentos de abate de aves registrados no SIF. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'A respeito das recomendações de vigilância e controle da Leishmaniose Visceral, que diferem conforme a classificação epidemiológica dos municípios, analise: I. Os municípios silenciosos devem focar na vigilância de reservatórios domésticos, com inquéritos sorológicos amostrais anuais da população canina, sendo esse acompanhamento suficiente onde não há registro da doença. II. Os municípios com transmissão esporádica devem focar na vigilância entomológica e de reservatórios domésticos, com levantamentos entomológicos e inquéritos sorológicos amostrais anuais; recomenda-se eutanásia dos cães sororreagentes identificados por inquéritos censitários anuais. III. Os municípios com transmissão moderada e intensa devem focar na vigilância entomológica e de reservatórios domésticos, com monitoramento entomológico e controle químico vetorial por dois ciclos anuais de inseticidas de ação residual. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 3),
  ('Doenças Infecciosas e Parasitárias', 'A brucelose é uma doença infectocontagiosa crônica causada por bactérias do gênero Brucella, de notificação obrigatória, controlada pelo PNCEBT. Uma das medidas de prevenção são as vacinas B19 e RB51. Assinale a opção que apresenta, corretamente, a situação em que se deve aplicar a vacina B19.', '["Somente em fêmeas herbívoras a partir de 3 meses.","Somente em fêmeas bovinas e bubalinas de 3 a 8 meses.","Somente em bovinos de ambos os sexos, a partir de 6 meses.","Estrategicamente em machos bovinos e bubalinos a partir de 4 meses.","Em todos os animais do rebanho (bovinos e bubalinos) maiores de 3 meses."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'A brucelose e a tuberculose são doenças bacterianas cujo diagnóstico deve ser feito por profissionais certificados. Assinale a opção que indica como os animais reagentes positivos para brucelose ou tuberculose devem ser identificados.', '["Os animais devem ser tatuados na face interna da orelha esquerda com um \"P\".","Os animais devem ser identificados por meio de brincos numerados e registrados em formulários específicos.","Os animais devem ser marcados a ferro candente ou nitrogênio líquido, no lado direito da cara, com um \"P\".","Os animais devem ser marcados a ferro candente ou nitrogênio líquido, próximo à região escapular direita, com um \"P\".","Os animais devem ser identificados por meio de resenha registrada e separados em piquetes específicos para os animais infectados."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'Em se tratando de defesa sanitária animal, a notificação da suspeita ou ocorrência de doença listada no Anexo da Instrução Normativa 50/2013 é obrigatória', '["somente para médicos veterinários.","somente para médicos veterinários, biólogos e biomédicos que atuem em diagnóstico de doenças de animais.","somente para profissionais que atuem na área de diagnóstico, ensino ou pesquisa em saúde animal.","somente para médicos veterinários, zootecnistas e técnicos agrícolas registrados em conselho de classe profissional.","para qualquer cidadão, independentemente de sua formação profissional ou situação de registro em conselho de classe."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'Assinale a opção que indica duas enfermidades caracterizadas como doenças erradicadas ou nunca registradas no país, que requerem notificação imediata de caso suspeito ou diagnóstico laboratorial, segundo a Instrução Normativa 50/2013.', '["Leucose enzoótica bovina e Varíola bovina.","Exantema genital equino e Adenomatose pulmonar ovina.","Brucelose por Brucella melitensis e Miíase por larvas de Chrysomya bezziana.","Brucelose (Brucella suis) e Febre Q.","Paratuberculose e Mixomatose."]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'As Encefalopatias Espongiformes Transmissíveis (EET) são doenças neurodegenerativas do Sistema Nervoso Central, regulamentadas pela IN SDA nº 18/2002. Segundo essa norma, assinale a opção que apresenta a situação em que o laboratório deve encaminhar material para diagnóstico de EET.', '["Deverá encaminhar, obrigatoriamente, as amostras de material encefálico de animais investigados com idade superior a 24 meses (bovinos) e 12 meses (ovinos e caprinos), que resultaram negativas para raiva.","Deverá encaminhar, obrigatoriamente, as amostras de material encefálico de bovinos, bubalinos, pequenos ruminantes e equinos investigados com idade superior a 10 meses, negativas para raiva.","Deverá encaminhar, obrigatoriamente, as amostras de material encefálico de bovinos/bubalinos e suínos e fragmentos da terceira pálpebra ou prega anorretal de pequenos ruminantes investigados com idade superior a 6 meses.","Deverá encaminhar, obrigatoriamente, todas as amostras de material encefálico de animais investigados que resultaram negativas para raiva.","Deverá encaminhar as amostras de material encefálico de animais herbívoros investigados negativas para raiva, somente quando houver suspeita de EET."]'::jsonb, 0),
  ('Doenças Infecciosas e Parasitárias', 'Segundo a Instrução Normativa 50/2013, assinale a opção que indica duas enfermidades caracterizadas como "doenças que requerem notificação mensal de qualquer caso confirmado".', '["Raiva e língua azul.","Ectima contagiosa e coccidiose.","Mormo e anemia infecciosa equina.","Febre do Vale do Rift e paratuberculose.","Febre do Nilo Ocidental e influenza aviária."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'O uso de EPIs e o respeito às boas práticas de aplicação de produtos químicos são essenciais para a saúde dos profissionais de controle de pragas, em especial roedores. Analise: I. Na aplicação de iscas rodenticidas granuladas em ponto de iscagem, devem ser usadas luvas impermeáveis de uso profissional. II. Para aplicação de iscas impermeáveis em bocas de lobo, galerias ou postos de visita, devem ser usadas luvas de PVC de uso profissional de cano longo. III. Para aplicação de rodenticidas em pó de contato, deve-se usar calça, camisa de manga longa, boné ou touca árabe, capacete e botina de segurança com biqueira de aço. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'A suspeita ou ocorrência de qualquer doença listada no Anexo da IN 50/2013 deve ser notificada imediatamente, no prazo máximo de 24 horas de seu conhecimento. A respeito do "momento" para a notificação, analise: I. Quando ocorrer pela primeira vez ou reaparecer no país, zona ou compartimento declarado oficialmente livre. II. Quando qualquer nova cepa de agente patogênico ocorrer pela primeira vez no país, zona ou compartimento. III. Quando ocorrerem mudanças repentinas e inesperadas nos parâmetros epidemiológicos (distribuição, incidência, morbidade ou mortalidade) de doença que já ocorre no país. Está correto o que se afirma em', '["I, apenas.","I e II, apenas.","I e III, apenas.","II e III, apenas.","I, II e III."]'::jsonb, 4),
  ('Produção Animal e Zootecnia', 'Um programa de planejamento e controle de dejetos gerados pela suinocultura considera cinco etapas: produção, coleta, armazenagem, tratamento, distribuição e uso dos dejetos. "Sua função principal é a degradação da carga orgânica contida nos dejetos. Funciona em condições anaeróbias, produzindo um efluente líquido (biofertilizante) e gerando biogás." Com base no texto, essa função pertence ao(à)', '["filtrador.","biodigestor.","decantador.","composteira.","lagoa de decantação."]'::jsonb, 1),
  ('Fisiologia e Ciências Básicas', 'Neurônios são células altamente especializadas, com axônios que podem atingir mais de um metro de comprimento, desenvolvendo um sistema eficiente de transporte intracelular. Sobre o transporte axonal, assinale a afirmativa correta.', '["A toxina tetânica alcança o sistema nervoso central via transporte axonal.","O vírus da raiva bloqueia o transporte axonal, diminuindo principalmente a atividade de neurônios inibitórios.","O transporte de componentes ocorre ao longo de filamentos de actina, resultante da polimerização de actina globular.","Há dois tipos de transporte axonal: o anterógrado, que carrega informação eferente, e o retrógrado, com informações sensoriais.","A base da movimentação de componentes ao longo do axônio são as propriedades de ligação e o alosterismo das proteínas, sem gasto de energia."]'::jsonb, 0),
  ('Fisiologia e Ciências Básicas', 'A bioinformática é uma área interdisciplinar de crescente importância na análise de dados biológicos. Assinale a opção que indica um uso prático dessa área na Medicina Veterinária.', '["Criar algoritmos para analisar sequências genéticas e inferir relações evolutivas entre agentes infecciosos a partir de big data genômico.","Programar gráficos em Python para superar limitações de outros gerenciadores de dados, focando na visualização de resultados experimentais.","Analisar dados de PCR em Excel para determinar ponto de corte e identificar casos positivos de uma doença infecciosa em uma propriedade rural.","Empregar ferramentas online para calcular o tamanho amostral de um experimento com camundongos.","Utilizar o software R para criar uma curva de Kaplan-Meier com casos de mortalidade por tumor de mama em um hospital veterinário."]'::jsonb, 0),
  ('Fisiologia e Ciências Básicas', 'Em maio de 2025, a IAGRO do Mato Grosso do Sul divulgou nota técnica informando que 3.049 bovinos morreram por hipotermia no Estado, em 2024. A hipotermia ocorre quando os mecanismos de produção e conservação de calor falham em impedir a queda da temperatura corporal. Assinale a opção que descreve corretamente o funcionamento de um desses mecanismos.', '["Animais jovens apresentam tecido adiposo marrom, que tem um importante papel como isolante térmico.","A piloereção favorece a movimentação do ar próxima à pele, aumentando a troca de calor por convecção.","Diminuição da liberação de tiroxina diminui o metabolismo corporal, economizando energia para o corpo lidar com o frio.","Músculos antagonistas são alternadamente ativados para produção de calor por gasto de energia, sem gerar movimento útil.","Vasodilatação superficial aumenta o fluxo de calor para que as regiões periféricas não sofram rapidamente os efeitos da queda de temperatura."]'::jsonb, 3),
  ('Fisiologia e Ciências Básicas', 'A discinesia ciliar primária é uma condição hereditária que compromete o funcionamento dos cílios na superfície celular, podendo causar rinite, sinusite e pneumonia. Em condições normais, o batimento dos cílios', '["otimiza o encontro de patógenos com os macrófagos intra-alveolares.","favorece a distribuição do vapor d''água no ar inspirado, prevenindo o ressecamento das vias aéreas.","provoca o turbilhonamento do ar para que as partículas possam se prender ao muco antes de atingir o alvéolo.","previne o aumento da viscosidade do muco, diminuindo a luz das vias aéreas o que demanda maior esforço inspiratório.","promove o deslocamento de partículas presas ao muco em direção à glote para serem deglutidas e neutralizadas pelo trato digestório."]'::jsonb, 4),
  ('Fisiologia e Ciências Básicas', 'Os ruminantes aproveitam fontes de nitrogênio não proteico (NNP), como a ureia, devido à ação da microbiota presente nos pré-estômagos. Sobre os aminoácidos absorvidos no intestino desses animais, assinale a afirmativa correta.', '["O trato digestivo de ruminantes não é capaz de aproveitar aminoácidos provenientes de fontes não proteicas.","As bactérias do rúmen são fonte importante de aminoácidos essenciais e são digeridas no abomaso e no intestino.","A maior parte dos aminoácidos absorvidos no intestino dos ruminantes provém da digestão das proteínas dietéticas no rúmen.","A ureia excretada na urina é a principal forma de aproveitamento do nitrogênio no metabolismo proteico de ruminantes.","A proteína microbiana é fermentada no rúmen, liberando aminoácidos livres que são diretamente absorvidos pela parede ruminal."]'::jsonb, 1),
  ('Fisiologia e Ciências Básicas', 'A barreira hematoencefálica tem base anatômica com capilares do tipo contínuo, junções intercelulares firmes, ausência de poros e prolongamentos astrocíticos ao redor do endotélio. Assinale a opção que apresenta a propriedade química que mais favoreceria a difusão passiva de um medicamento do sangue para o SNC, sem depender de mecanismos específicos de transporte.', '["Gases apolares ou pouco polares.","Peptídeo com até cinco aminoácidos.","Molécula com estrutura mais parecida com a glicose.","Molécula pequena ligeiramente positiva no pH fisiológico.","Molécula pequena ligeiramente negativa no pH fisiológico."]'::jsonb, 0),
  ('Fisiologia e Ciências Básicas', 'Quando um animal ingere muita água, ocorre aumento do volume e diminuição da osmolaridade do ambiente interno do corpo, demandando eliminação de água sem eliminar sais. Assinale a opção que explica corretamente um dos mecanismos acionados nessa condição.', '["O aumento do volume interno é percebido nos barorreceptores que induzem uma resposta simpática, aumentando a produção de urina.","O aumento do volume interno diminui a hiperosmolaridade medular característica do rim, diminuindo a capacidade de retenção de líquido, levando à sua maior eliminação pela urina.","O aumento do volume interno se reflete em maior enchimento atrial, induzindo a liberação de peptídeo natriurético atrial, que promove a eliminação de água nos rins por osmose.","A queda da osmolaridade é detectada na mácula densa, que ativa o sistema renina-angiotensina-aldosterona, aumentando a pressão arterial para garantir a perfusão adequada dos tecidos.","A queda da osmolaridade é detectada no hipotálamo, havendo menor liberação de ADH, que promove menor expressão de aquaporinas nos túbulos coletores renais, diminuindo a reabsorção de água."]'::jsonb, 4),
  ('Fisiologia e Ciências Básicas', 'A forte interação das moléculas de água na superfície interna dos alvéolos, associada ao seu formato aproximadamente esférico, faz com que essa estrutura tenda ao colapso. Assinale a opção que apresenta corretamente o mecanismo fisiológico que contorna esse problema durante a inspiração.', '["Os pneumócitos tipo I absorvem água de forma contínua, evitando seu acúmulo na superfície interna alveolar.","Os pneumócitos tipo II produzem um composto de natureza anfipática capaz de interagir com a água, diminuindo a tensão superficial.","Macrófagos intra-alveolares produzem um surfactante que impede que moléculas de água formem uma camada sobre a superfície alveolar.","A tensão superficial dos alvéolos é controlada devido à pressão negativa do espaço pleural, que mantém todos os alvéolos já dilatados.","Uma parte do muco produzido por células caliciformes presentes nos bronquíolos terminais atinge o alvéolo, diminuindo a tensão superficial."]'::jsonb, 1),
  ('Fisiologia e Ciências Básicas', 'Sobre as camadas da epiderme saudável, essenciais para identificar lesões como carcinoma de células escamosas, carcinoma basocelular ou afecções acantolíticas: ( ) O estrato córneo é composto predominantemente por queratina e sua espessura varia conforme as diferentes regiões do corpo. ( ) O estrato espinhoso pode ser identificado à microscopia de luz pelas espículas de queratina que permanecem enrijecidas pela fixação por formol. ( ) O estrato basal é formado por células tronco, com grande capacidade de multiplicação e autorreposição. As afirmativas são, na ordem apresentada, respectivamente,', '["V – V – F.","V – F – V.","F – V – V.","F – F – V.","F – V – F."]'::jsonb, 1),
  ('Fisiologia e Ciências Básicas', 'A comunicação entre células do sistema nervoso e entre células da musculatura lisa do trato gastrointestinal ocorre por dois tipos diferentes de sinapse. Considerando as características das sinapses química e elétrica, assinale a afirmativa correta.', '["Tanto a sinapse elétrica quanto a sinapse química podem ser excitatórias ou inibitórias.","No sistema nervoso periférico, a sinapse química é encontrada apenas em gânglios nervosos.","A sinapse elétrica envolve os mesmos neurotransmissores presentes no sistema nervoso periférico, ou seja, adrenalina/noradrenalina e acetilcolina.","A sinapse elétrica permite transmissão rápida e bidirecional do sinal por meio de junções comunicantes, enquanto a sinapse química é mais controlada e unidirecional.","A sinapse química depende do cálcio para induzir a liberação dos neurotransmissores, enquanto a base da comunicação pela sinapse elétrica é a difusão direta do cálcio de uma célula para a outra."]'::jsonb, 3),
  ('Fisiologia e Ciências Básicas', 'O eletrocardiograma (ECG) registra a atividade elétrica do coração e reflete a ordem de sua ativação. Assinale a opção que relaciona, corretamente, os elementos do ECG com eventos cardíacos específicos.', '["As ondas P e T representam a repolarização dos átrios e dos ventrículos, respectivamente.","O aumento do intervalo PR é um indício de aumento da velocidade de condução elétrica entre os átrios e os ventrículos.","O complexo QRS é o evento gráfico de maior amplitude, pois corresponde à diástole elétrica do ventrículo, que tem mais massa que os átrios.","Na ausência da onda T, espera-se que o complexo QRS esteja aumentado de forma compensatória, indicando o mecanismo de Frank-Starling.","A ausência da onda P, quando os outros elementos estão presentes, é indicativo de que o nodo sinoatrial não está funcional; nesse caso, espera-se que haja uma bradicardia."]'::jsonb, 4),
  ('Fisiologia e Ciências Básicas', 'A insulina é um hormônio pancreático essencial na regulação do metabolismo energético, facilitando a entrada da glicose nas células. No entanto, nem todas as células dependem da insulina para captar glicose. Assinale a opção que indica, corretamente, um tipo celular que depende da insulina para captar glicose e o motivo dessa dependência.', '["Enterócitos: porque são responsáveis por captá-la da luz intestinal e necessitam de transportadores de membrana altamente eficientes.","Neurônios: porque esse tipo celular tem alta demanda energética e a glicose necessita de transporte eficiente pelas proteínas expressas pela insulina.","Hepatócitos: porque na fase pós-absortiva necessitam disponibilizar esse nutriente no sentido contrário, liberando glicose a partir de glicogenólise e gliconeogênese.","Hemácias: porque, em mamíferos, como não apresentam núcleo, são altamente dependentes da glicose como fonte de energia e a insulina garante seu fornecimento.","Adipócitos: porque na fase pós-absortiva fornecem gordura como substrato energético, que não pode ser reconvertida em glicose."]'::jsonb, 4),
  ('Fisiologia e Ciências Básicas', 'A creatinina é um produto do metabolismo muscular naturalmente excretada na urina. A depuração (clearance) renal da creatinina é um excelente marcador da função renal porque ela corresponde, aproximadamente, à(ao)', '["capacidade de concentração de urina, uma vez que sua excreção é responsiva ao ADH.","fluxo urinário, uma vez que sua concentração na urina é semelhante à concentração plasmática.","fluxo plasmático renal, uma vez que é livremente filtrada nos glomérulos e, nos túbulos, não é reabsorvida e é completamente secretada.","taxa de filtração glomerular, uma vez que é livremente filtrada nos glomérulos e, nos túbulos, não é reabsorvida e é muito pouco secretada.","fluxo sanguíneo renal, uma vez que a creatinina exerce força osmótica e a retenção proporcional de líquido varia com a fração do débito cardíaco direcionado aos rins."]'::jsonb, 3),
  ('Fisiologia e Ciências Básicas', 'A função renal é regulada por uma combinação de mecanismos: a modulação neuroendócrina (regulação extrínseca) e o aparelho justaglomerular (regulação intrínseca). ( ) O aparelho justaglomerular é composto pela mácula densa, pelas células granulares justaglomerulares e pelas células mesangiais extraglomerulares. ( ) Cada néfron possui seu próprio aparelho justaglomerular, permitindo rápido ajuste individual, mas também promovendo integração sistêmica pelo sistema renina-angiotensina-aldosterona. ( ) A hipotensão arterial sistêmica estimula a atividade autonômica simpática, produzindo vasoconstrição que, nos rins, aumenta a filtração glomerular, garantindo a excreção renal mesmo com pressão baixa. As afirmativas são, na ordem apresentada, respectivamente,', '["V – V – F.","F – V – V.","V – F – F.","F – F – V.","V – V – V."]'::jsonb, 0),
  ('Fisiologia e Ciências Básicas', 'Um ciclo cardíaco é composto por sístole e diástole, com fases identificadas como contração isovolumétrica, período de ejeção, relaxamento isovolumétrico e enchimento ventricular. Considerando essas fases, assinale a afirmativa correta.', '["O período de ejeção inicia-se com a abertura da valva mitral.","A pressão mínima no ventrículo, durante a diástole, é 80 mmHg.","A contração isovolumétrica termina com a abertura da valva aórtica.","O período de enchimento inicia-se com o fechamento da valva mitral.","O relaxamento isovolumétrico termina com a abertura da valva mitral."]'::jsonb, 2),
  ('Fisiologia e Ciências Básicas', 'Um animal que sofre uma grave hemorragia tem diminuição abrupta do volume de sangue circulante, causando queda da pressão sanguínea e comprometendo a perfusão dos tecidos. Assinale a opção que explica corretamente um dos mecanismos que o organismo usa para reverter essa hipotensão.', '["A diminuição do volume circulante reflete-se na diminuição do retorno venoso, ativando o mecanismo de Frank-Starling para ejetar com mais força o sangue para a aorta.","Os átrios detectam o menor volume sanguíneo dentro do coração e aumentam a liberação de peptídeo natriurético atrial, que atua nos rins para prevenir a perda de água pela urina.","Em resposta à diminuição da pressão, a fim de diminuir a resistência periférica total, ocorre uma vasodilatação periférica.","A diminuição da pressão detectada nos barorreceptores ativa a resposta simpática que aumenta a frequência cardíaca, aumentando o débito cardíaco e, consequentemente, a pressão arterial.","A diminuição da perfusão tecidual leva a um acúmulo de resíduos metabólicos locais que estimulam diretamente a contração da musculatura lisa das arteríolas, aumentando a resistência periférica total."]'::jsonb, 3),
  ('Fisiologia e Ciências Básicas', 'Sobre o amido, polissacarídeo formado por unidades de glicose ligadas por ligações glicosídicas alfa-1,4: ( ) O amido não sofre digestão enzimática no estômago dos cães. ( ) O primeiro processo significativo de quebra química do amido no trato gastrointestinal dos cães ocorre por ação da tripsina no duodeno. ( ) A glicose liberada na fase de membrana da digestão intestinal é absorvida pelos enterócitos principalmente por cotransporte com sódio. As afirmativas são, na ordem apresentada, respectivamente,', '["V – V – F.","F – V – V.","V – F – V.","F – F – V.","F – V – F."]'::jsonb, 2),
  ('Fisiologia e Ciências Básicas', 'Durante o atendimento clínico de animais de companhia, é comum observar sinais como febre, secreções mucosas e alterações inflamatórias na pele ou mucosas, refletindo a ativação dos mecanismos de defesa do organismo. Assinale a afirmativa correta sobre os principais tipos de resposta imune em animais.', '["A inflamação é característica da imunidade adaptativa, pois ocorre apenas após a diferenciação de monócitos em macrófagos.","A resposta adaptativa depende da ativação de receptores do tipo Toll-like (TLRs) presentes em células da imunidade inata para iniciar sua ação específica.","As células natural killers (NK) fazem parte da imunidade adaptativa, pois reconhecem antígenos específicos apresentados por células infectadas.","A imunidade inata pode ser transmitida passivamente aos neonatos por meio da placenta ou do colostro, conferindo proteção específica nas primeiras semanas de vida.","A imunidade inata compreende mecanismos como barreiras epiteliais, renovação celular contínua e produção de muco, que atuam de forma imediata contra agentes invasores."]'::jsonb, 4),
  ('Fisiologia e Ciências Básicas', 'O hormônio do crescimento (GH), produzido pela adeno-hipófise, exerce múltiplas funções metabólicas e anabólicas. Distúrbios em sua produção ou ação podem levar a nanismo hipofisário, acromegalia e alterações metabólicas importantes. Assinale a afirmativa correta sobre a fisiologia e o papel do GH.', '["O GH promove a lipogênese e estimula a produção hepática de glicose no fígado e no tecido adiposo.","Os níveis plasmáticos de GH permanecem estáveis ao longo do dia para não provocar um desequilíbrio metabólico.","O GH aumenta a sensibilidade das células à insulina, facilitando a captação de glicose pelos tecidos periféricos.","O GH faz parte do eixo hipotálamo-hipófise-fígado, sendo que grande parte dos seus efeitos anabólicos é mediada pelo IGF-1.","A secreção de GH é regulada por feedback negativo direto, em que o aumento de GH no sangue inibe sua secreção na adeno-hipófise."]'::jsonb, 3),
  ('Doenças Infecciosas e Parasitárias', 'Diante da crescente resistência de helmintos aos fármacos anti-helmínticos, o desenvolvimento de vacinas contra esses parasitas se tornou uma estratégia promissora no controle parasitário. ( ) Produtos secretados por helmintos para evasão do sistema imunológico são bons candidatos como antígeno vacinal. ( ) Um exemplo de utilização de antígeno oculto é a produção de vacina contra proteínas intestinais de helmintos hematófagos. ( ) Vacinas contra estágios larvais não são viáveis, pois induzem formação de granuloma reativo exuberante que pode ser prejudicial ao hospedeiro. As afirmativas são, na ordem apresentada, respectivamente,', '["F – F – V.","F – V – F.","V – F – F.","V – V – F.","V – V – V."]'::jsonb, 3),
  ('Clínica e Cirurgia de Pequenos Animais', 'Na rotina clínica de um Hospital Veterinário, um cão de 8 anos de idade é diagnosticado com Diabetes Mellitus tipo I, caracterizada pela destruição das células beta pancreáticas e deficiência absoluta de insulina. Sobre as principais alterações metabólicas esperadas, assinale a afirmativa correta.', '["A ausência de insulina resulta em aumento da captação de glicose pelas células musculares e adiposas, levando à hipoglicemia e à diminuição da gliconeogênese hepática.","A condição caracteriza-se primariamente por uma resistência tecidual à ação da insulina, resultando em níveis elevados de insulina circulante ineficazes na redução da glicemia.","A deficiência de insulina promove a ativação da gliconeogênese no fígado e músculos, visando armazenar o excesso de glicose circulante para corrigir a hiperglicemia.","O principal efeito da falta de insulina é a supressão da secreção de glucagon, o que impede a mobilização de reservas energéticas.","A falta de insulina impede a entrada de glicose nas células que dependem desse hormônio, levando à hiperglicemia, junto com intensificação da lipólise e da proteólise."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Em bovinos, a eficiência do aproveitamento de dietas ricas em fibras é amplamente atribuída à complexidade de seu sistema digestório e à simbiose com uma vasta população microbiana. Com base na fisiologia da digestão de ruminantes, assinale a afirmativa correta.', '["O abomaso é o principal sítio de absorção dos Ácidos Graxos Voláteis (AGVs) produzidos pela digestão microbiana, devido à sua estrutura de pregas.","A formação do bolo alimentar e a regurgitação para a ruminação ocorrem exclusivamente no omaso, garantindo a redução do tamanho das partículas.","O omaso tem como principal função a fermentação microbiana da celulose, gerando grandes quantidades de gases posteriormente absorvidos para evitar timpanismo.","A maior parte da digestão de proteínas e amido, e a subsequente absorção de glicose e aminoácidos, ocorrem primariamente no abomaso, devido à presença de enzimas digestivas potentes.","No rúmen, ocorre a intensa fermentação de carboidratos, celulose e hemicelulose por bactérias, fungos e protozoários, resultando na produção de AGVs, absorvidos diretamente pela parede ruminal e que constituem a principal fonte de energia do ruminante."]'::jsonb, 4),
  ('Clínica e Cirurgia de Pequenos Animais', 'Um cão, vítima de atropelamento, é admitido no setor de emergência apresentando mucosas pálidas, TPC prolongado (>2 segundos), extremidades frias, taquicardia (FC 160 bpm) e pulso femoral fraco e rápido, com suspeita de choque hipovolêmico. Assinale a opção que descreve a conduta terapêutica de ação imediata e prioritária para a estabilização do paciente.', '["Realizar uma transfusão sanguínea imediata, para corrigir a perda de proteínas plasmáticas e a anemia.","Iniciar fluidoterapia intravenosa lenta com solução de glicose a 5%, visando repor a volemia e prevenir a hipoglicemia.","Administrar analgésicos opioides em doses elevadas para controle da dor severa antes de avaliar a extensão das lesões.","Administrar antimicrobianos de amplo espectro por via endovenosa e aguardar os resultados dos exames laboratoriais antes de qualquer outra intervenção.","Iniciar fluidoterapia intravenosa rápida (em bolus) com cristaloides isotônicos (ex: Ringer Lactato ou solução fisiológica 0,9%), por meio de acesso venoso calibroso, para restaurar o volume intravascular e a perfusão tecidual."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'Um cavalo da raça Quarto de Milha, com histórico de consumo irregular de concentrados, é atendido em sua propriedade com sinais agudos de cólica: inquietação, rolar no chão, escoiceamento abdominal e ausência de fezes. Ao exame: FC 60 bpm, FR 30 irpm, mucosas congestas e TPC prolongado (3 segundos). Assinale a opção que descreve as condutas diagnósticas e de manejo apropriadas no campo.', '["Administrar uma alta dose de analgésico e observar a resposta por algumas horas antes de considerar qualquer outra intervenção ou transporte.","Priorizar a auscultação abdominal e, se os sons intestinais estiverem ausentes em todos os quadrantes, iniciar tratamento com laxantes orais e fluidos por sonda nasogástrica, pois indica compactação simples resolvível no campo.","Priorizar o exame retal e a sondagem nasogástrica para identificar distensão gasosa ou acúmulo de conteúdo gástrico, além de avaliar a intensidade da dor e a resposta à analgesia, auxiliando na decisão entre tratamento clínico ou cirúrgico.","Priorizar a administração de fluidos por via oral, utilizando soluções hipotônicas para promover a hidratação celular e aliviar rapidamente a distensão abdominal.","Realizar um ultrassom abdominal completo e detalhado no campo para identificar a localização exata da lesão e somente então decidir sobre o tratamento."]'::jsonb, 2),
  ('Clínica e Cirurgia de Pequenos Animais', 'Cão da raça Labrador Retriever de 7 anos apresenta crises convulsivas recorrentes (perda de consciência, tremores generalizados, salivação, vocalização, 1-2 min, seguidas de desorientação pós-crise), a cada 3-4 semanas, sem fatores precipitantes. Exame neurológico interictal normal; investigação excluiu causas metabólicas, tóxicas e estruturais. Suspeita: epilepsia idiopática. Assinale a afirmativa correta sobre o manejo.', '["O diagnóstico definitivo em cães é estabelecido principalmente pela detecção de uma lesão estrutural específica no encéfalo por ressonância magnética.","O tratamento medicamentoso deve ser iniciado imediatamente após a primeira crise convulsiva, independentemente da frequência ou gravidade, com benzodiazepínicos como terapia de manutenção a longo prazo.","As crises descritas são características de convulsões focais, e o manejo farmacológico é indicado se o animal apresentar mais de uma crise por dia, sendo a gabapentina a droga de primeira escolha para monoterapia.","É um diagnóstico de exclusão e o tratamento farmacológico é recomendado quando as crises são frequentes (mais de uma a cada 6-8 semanas) ou ocorrem em clusters, sendo o fenobarbital e/ou brometo de potássio as opções de primeira linha.","É uma condição autolimitante que, na maioria dos casos, se resolve espontaneamente ao longo do tempo, necessitando tratamento medicamentoso apenas durante as crises agudas."]'::jsonb, 3),
  ('Clínica e Cirurgia de Pequenos Animais', 'Uma equipe veterinária se prepara para realizar uma cirurgia abdominal em um gato. Considerando os princípios de assepsia e antissepsia essenciais em ambiente cirúrgico veterinário, assinale a afirmativa correta.', '["A paramentação cirúrgica da equipe tem como objetivo principal criar e manter uma barreira estéril entre a equipe cirúrgica e o campo operatório do paciente, prevenindo a transferência de microrganismos.","O método de esterilização por óxido de etileno para instrumentais termossensíveis é o mais indicado, dispensando o uso rotineiro de indicadores biológicos devido à sua alta penetração e eficácia.","A preparação antisséptica do campo cirúrgico com PVPI é preferível em procedimentos com alto risco de contaminação por matéria orgânica, por não ser inativada por sangue ou pus.","A tricotomia da área cirúrgica deve ser realizada com a maior proximidade possível à incisão, podendo-se usar lâmina de barbear estéril para otimizar a superfície.","A esterilização por autoclavagem gravitacional a 121°C por 15 minutos é o parâmetro padrão para todos os pacotes de instrumentais cirúrgicos metálicos reutilizáveis."]'::jsonb, 0),
  ('Clínica e Cirurgia de Pequenos Animais', 'No pós-operatório de excisão de massa abdominal, um cão de 5 anos retorna inquieto, lambendo a incisão com frequência, e removeu alguns pontos da sutura, expondo uma pequena área da ferida. Assinale a afirmativa correta sobre complicações pós-operatórias em cirurgias de tecidos moles.', '["A deiscência parcial de ferida cirúrgica é comumente manejada por desbridamento cuidadoso e fechamento por segunda intenção, uma vez que a ressutura primária precoce aumenta o risco de infecção.","A prevenção da automutilação da ferida cirúrgica é fundamental e inclui o uso de colar elizabetano ou roupa cirúrgica, associado a manejo eficaz da dor pós-operatória para reduzir o desconforto e o impulso de manipular a incisão.","Seromas pós-operatórios de qualquer tamanho e localização devem ser prontamente drenados por dreno de Penrose ou aspiração repetida, pois a permanência de fluidos leva à infecção.","A automutilação da ferida é frequentemente motivada por prurido ou dor localizada, e opioides sistêmicos oferecem prevenção mais completa que a barreira física de um colar elizabetano.","A infecção da ferida, evidenciada por hiperemia e edema local, requer coleta de material para cultura, iniciando-se antibióticos sistêmicos somente após a obtenção desses resultados."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'Um potro recém-nascido de 50kg, com diarreia severa há aproximadamente 24 horas, anorexia e prostração, é recebido no Setor de Grandes Animais. Ao exame: letargia acentuada, olhos encovados, prega cutânea que persiste por 3 segundos. Desidratação estimada em 8%. Sobre o manejo inicial e o cálculo de fluidos, assinale a afirmativa correta.', '["O volume total de fluido para correção da desidratação (8%) do potro é de 4,0 litros, suficiente para as primeiras 24 horas de tratamento.","Para corrigir a desidratação (8%) e suprir as necessidades de manutenção (5 mL/kg/hora) nas primeiras 24 horas, o potro requer um volume total de, aproximadamente, 10,0 litros de fluido intravenoso.","O potro necessita de aproximadamente 2,5 litros de fluido por via oral para as necessidades de manutenção diária, sendo que a correção da desidratação pode ser realizada eficazmente por essa mesma via.","O tipo de fluido de escolha para iniciar a reidratação é uma solução hipotônica como glicose a 5%, visando à expansão rápida do volume intravascular sem risco de sobrecarga de sódio.","Em casos de desidratação severa como este, a fluidoterapia deve ser administrada de forma lenta e gradual nas primeiras 12 horas, para prevenir sobrecarga cardíaca e progressão de desequilíbrios eletrolíticos."]'::jsonb, 1),
  ('Anestesiologia e Farmacologia', 'Um cão, SRD, macho, 8 anos, será submetido a osteossíntese para correção de fratura de fêmur. Na avaliação pré-anestésica, é portador de doença cardíaca crônica (IVM) controlada com medicação oral, ocasionalmente causando tosse e leve intolerância ao exercício intenso. Exames laboratoriais dentro dos limites; ecocardiograma compatível com IVM, sem descompensação aguda. Considerando a classificação ASA e sua aplicação na Medicina Veterinária, assinale a afirmativa correta.', '["O paciente deve ser classificado como ASA II, pois a doença cardíaca controlada representa um risco sistêmico leve, que não impede um protocolo anestésico padrão com monitoramento básico.","A classificação correta para este paciente é ASA I, visto que a doença cardíaca está sob controle medicamentoso e os exames laboratoriais estão normais.","O paciente se enquadra na classificação ASA IV, dado que qualquer doença cardíaca crônica, independentemente do grau de controle, implica risco anestésico de vida constante.","A classificação ASA para este caso é ASA V, uma vez que a presença de doença cardíaca crônica torna o animal um paciente moribundo com prognóstico extremamente reservado.","Este animal é um ASA III, pois a doença cardíaca crônica, mesmo controlada, constitui uma doença sistêmica moderada que limita a atividade, demandando protocolo anestésico cuidadosamente adaptado e monitoramento avançado."]'::jsonb, 4),
  ('Anestesiologia e Farmacologia', 'Durante uma gastrotomia exploratória em um cão da raça Boxer, sob anestesia inalatória com isoflurano, o anestesista observa: pressão arterial média (PAM) 50 mmHg, FC 60 bpm, FR 6 rpm, capnografia EtCO2 55 mmHg, SpO2 92%. Considerando o monitoramento anestésico e o manejo de intercorrências, assinale a afirmativa correta.', '["A hipotensão (PAM 50 mmHg) é uma emergência que compromete a perfusão tecidual. A ação primária deve ser um bolus rápido de fluidos intravenosos, seguido de vasopressores, independentemente do agente inalatório em uso.","A hipoventilação severa (FR 6, EtCO2 55) com hipoxemia (SpO2 92%) exige intervenção imediata: ventilação manual assistida e aumento do fluxo de oxigênio, priorizando-se, inicialmente, a manutenção da concentração de isoflurano.","O conjunto de achados sugere profundidade anestésica excessiva e/ou depressão cardiovascular/respiratória, devendo ser corrigido primariamente pela administração de fármacos estimulantes e aumento da oferta de oxigênio.","A bradicardia (FC 60) é fator limitante do débito cardíaco. A administração de um agente cronotrópico positivo como a atropina é a conduta primária para elevar a FC e controlar a pressão arterial.","A SpO2 de 92% e o EtCO2 de 55 mmHg sinalizam hipoventilação e troca gasosa deficiente. A correção imediata envolve reduzir a concentração do anestésico inalatório, aumentar a ventilação minuto por ventilação manual/mecânica assistida e aumentar a concentração de oxigênio inspirada."]'::jsonb, 4),
  ('Patologia Geral e Diagnóstico', 'Em uma necropsia de bovino que morreu subitamente após pneumonia grave e pericardite, observou-se que a superfície do pericárdio está recoberta por uma camada espessa, rugosa e esbranquiçada, com aspecto de "pão com manteiga", que adere fortemente ao miocárdio. Ao destacá-la, rompe-se em filamentos, deixando as superfícies subjacentes rugosas e hiperêmicas. Assinale a opção que descreve corretamente este processo inflamatório.', '["Inflamação catarral, caracterizada pela produção excessiva de muco por glândulas mucosas.","Inflamação purulenta (supurativa), com acúmulo de grande quantidade de pus (material cremoso, amarelado-esverdeado).","Inflamação hemorrágica, com grande extravasamento de hemácias para os tecidos, resultando em áreas de coloração vermelha intensa.","Inflamação fibrinosa, onde o extravasamento massivo de fibrinogênio para o exsudato resulta na formação de fibrina em superfícies serosas, causando aderências e aspecto rugoso.","Inflamação granulomatosa, evidenciada pela formação de nódulos ou massas bem delimitadas, com aspecto caseoso ou firme."]'::jsonb, 3),
  ('Patologia Geral e Diagnóstico', 'Um médico-veterinário é confrontado com um cão com histórico de inchaço progressivo na face e mandíbula, sem melhora com tratamentos sintomáticos, suspeitando de doença neoplásica ou inflamatória grave. Considerando as técnicas diagnósticas empregadas na Patologia Veterinária, assinale a afirmativa correta.', '["A histopatologia é considerada o \"padrão ouro\" para o diagnóstico definitivo de várias doenças, especialmente na diferenciação entre processos inflamatórios, hiperplásicos e neoplásicos, e para a classificação de tumores.","A imunohistoquímica é utilizada para identificar agentes infecciosos em tecidos, não tendo aplicação na classificação de neoplasias ou determinação de marcadores prognósticos.","O exame post-mortem (necropsia) é um procedimento invasivo focado na identificação de lesões macroscópicas e pode ser usado para diagnóstico definitivo de processos neoplásicos.","A citopatologia, análise morfológica de tecidos, é um método minimamente invasivo e de baixo custo, considerada o método definitivo para diagnóstico e classificação de processos neoplásicos.","A biópsia incisional é o método preferencial para remoção completa de massas suspeitas, permitindo diagnóstico e tratamento definitivo em uma única intervenção."]'::jsonb, 0),
  ('Patologia Geral e Diagnóstico', 'Um cão Shih Tzu de 5 anos apresenta perda de peso progressiva, vômitos intermitentes e massa abdominal discreta à palpação. Radiografias abdominais revelam opacidade de tecidos moles na região cranial do abdômen, com deslocamento de alças intestinais. Sobre as técnicas de diagnóstico por imagem para investigação de massas abdominais: ( ) A ultrassonografia caracteriza a estrutura interna de massas de tecidos moles, avaliando ecogenicidade, vascularização e relação com órgãos adjacentes, sendo método de escolha inicial para guiar biópsias. ( ) A tomografia computadorizada (TC) permite avaliação tridimensional da massa e sua relação com estruturas vasculares e ósseas, estadiamento de neoplasias e mensuração da atenuação tecidual em Unidades Hounsfield. ( ) O uso de contraste iodado em radiografia e TC, ou gadolínio em RM, pode melhorar a visualização de estruturas vasculares e a caracterização da massa. As afirmativas são, respectivamente,', '["V – V – V.","F – V – F.","V – V – F.","F – V – V.","V – F – V."]'::jsonb, 0),
  ('Patologia Geral e Diagnóstico', 'Considerando a interpretação dos biomarcadores renais e hepáticos em bioquímica clínica veterinária: ( ) A creatinina sérica é um marcador mais sensível de função glomerular do que o nitrogênio ureico sanguíneo (BUN), que pode sofrer influência do conteúdo proteico da dieta e de outros fatores extrarrenais. ( ) A atividade de Alanina Aminotransferase (ALT) pode elevar-se em decorrência de lesão muscular e/ou de lesão hepática. ( ) A concentração de bilirrubina total pode elevar-se em decorrência de hemólise, insuficiência hepática ou colestase, ou mesmo a combinação dessas três possibilidades. As afirmativas são, respectivamente,', '["V – V – V.","F – V – V.","V – V – F.","V – F – V.","F – F – V."]'::jsonb, 0),
  ('Patologia Geral e Diagnóstico', 'Uma cadela de 7 anos é atendida com prostração, anorexia e vômitos intermitentes há 3 dias, dor à palpação abdominal cranial. Na ultrassonografia, o baço apresenta aumento difuso de volume, ecotextura heterogênea com múltiplas áreas nodulares hipoecogênicas de contornos irregulares, cápsula irregular em algumas regiões; ao Doppler colorido, fluxo vascular desorganizado e de alta velocidade em algumas áreas nodulares. Assinale a alternativa correta sobre esses achados.', '["A presença de múltiplas áreas nodulares hipoecogênicas associadas à heterogeneidade difusa e aumento de volume indica quadro típico de inflamação crônica, incomum em neoplasias esplênicas.","Os achados são altamente sugestivos de uma neoplasia esplênica.","O uso do Doppler colorido não é relevante na avaliação de massas esplênicas, pois não diferencia lesões vascularizadas de lesões necróticas ou císticas.","Os achados descartam a possibilidade de neoplasia, sendo mais compatíveis com esplenite reativa benigna.","A heterogeneidade e irregularidade capsular observadas são achados inespecíficos sem valor diagnóstico relevante."]'::jsonb, 1),
  ('Patologia Geral e Diagnóstico', 'Em um laboratório de patologia clínica veterinária, os tubos de coleta a vácuo são padronizados por cores de tampa que indicam o tipo de anticoagulante ou aditivo, direcionando sua aplicação para diferentes análises. Assinale a afirmativa correta.', '["Para um hemograma completo em cães, o tubo de eleição é o de tampa vermelha, devido à presença de heparina, que preserva a morfologia celular por mais tempo.","O tubo de coleta com tampa azul contém citrato de sódio como anticoagulante e é o mais indicado para amostras destinadas a testes de coagulação.","Amostras destinadas a exames que avaliam a função hepática, como albumina e fatores de coagulação, devem ser preferencialmente coletadas em tubos com tampa roxa/lilás, devido à presença de EDTA.","Tubos sem anticoagulante, identificados por tampas verdes, são os mais indicados para análises hematológicas, pois evitam qualquer interferência com a integridade das células sanguíneas.","A heparina é o anticoagulante encontrado em tubos de tampa amarela, sendo estes os mais versáteis para a maioria dos exames bioquímicos e hematológicos combinados."]'::jsonb, 1),
  ('Patologia Geral e Diagnóstico', 'A urinálise é indispensável para a avaliação da função renal e detecção de diversas condições patológicas em animais. ( ) A proteinúria, avaliada pelo aumento da razão proteína:creatinina urinária (PCU), pode indicar doença renal, como a glomerulonefrite. ( ) A presença de cilindros céreos e granulares grosseiros no sedimento urinário pode indicar lesão nos túbulos renais. ( ) A presença de cristais de oxalato de cálcio na urina pode não ter importância clínica ou pode representar uma lesão de túbulo renal associada à hipocalcemia. As afirmativas são, respectivamente,', '["V – V – V.","V – F – V.","F – V – V.","V – V – F.","V – F – F."]'::jsonb, 0),
  ('Patologia Geral e Diagnóstico', 'Um cão com letargia e membranas mucosas pálidas apresenta hemograma: VG 12% (ref. 37-55%); Hb 3,6 g/dL (ref. 12-18); Hemácias 0,95 x10⁶/µL (ref. 5,5-8,5); VGM 114 fL (ref. 60-72); Reticulócitos 123x10³/µL (ref. <60x10³). No esfregaço: policromasia marcante, sinais de aglutinação e vários esferócitos. Assinale a afirmativa correta.', '["O animal apresenta anemia regenerativa e microcítica, sendo o VGM elevado um achado esperado para este tipo de anemia.","A anemia é classificada como não regenerativa devido à alta contagem de reticulócitos, e a aglutinação indica uma possível deficiência de ferro.","Os achados são compatíveis com anemia hemolítica imunomediada, caracterizada por anemia marcante, policromasia, esferocitose e aglutinação, com evidência de resposta medular.","A presença de esferócitos e a aglutinação são irrelevantes para o diagnóstico, sendo a principal alteração a hipocromasia evidenciada pelo baixo CHCM.","A diminuição do VG, Hb e He indica uma anemia arregenerativa, e o aumento do VGM sugere um erro na coleta da amostra."]'::jsonb, 2),
  ('Clínica e Cirurgia de Pequenos Animais', 'Um cão de grande porte, de meia-idade, apresenta dor na região lombossacral, fraqueza progressiva dos membros pélvicos, relutância em pular ou subir escadas e incontinência fecal e urinária intermitente. Ao exame: diminuição do tônus do esfíncter anal, perda do reflexo perineal e da sensibilidade na região da cauda, dor à palpação profunda na junção lombossacral. Assinale a opção que indica o provável diagnóstico.', '["Espondilomielopatia cervical caudal (Síndrome de Wobbler).","Polirradiculoneurite.","Mielopatia Degenerativa.","Síndrome da Cauda Equina.","Doença do Disco Intervertebral."]'::jsonb, 3),
  ('Clínica e Cirurgia de Pequenos Animais', 'Uma cadela SRD, de 8 anos, foi diagnosticada com piometra fechada há 3 dias, inicialmente com letargia, anorexia e leve distensão abdominal sem secreção vulvar. Exames complementares revelaram leucocitose acentuada com desvio à esquerda e sinais de injúria renal aguda (azotemia e isostenúria), com estado geral moderadamente comprometido. Considerando o quadro clínico e o objetivo de melhor prognóstico para resolução completa e minimização de complicações, assinale a abordagem terapêutica recomendada.', '["Tratamento médico com prostaglandinas e antibióticos, pois evita a cirurgia e possui alta taxa de sucesso mesmo em casos sistêmicos.","Início imediato de fluidoterapia intensiva e antibioticoterapia de amplo espectro, com reavaliação em 48 horas para considerar tratamento médico completo com prostaglandinas.","Tratamento conservador com fluidoterapia e suporte nutricional por uma semana, para estabilizar o paciente antes de qualquer intervenção específica.","Estabilização do paciente e laparotomia exploratória para drenagem uterina, preservando o útero sem necessidade de remoção completa.","Estabilização inicial do paciente e ovariohisterectomia (OSH) de emergência, pois oferece a resolução definitiva da infecção e da fonte de toxemia."]'::jsonb, 4),
  ('Saúde Pública e Legislação Veterinária', 'D.M. tem problema de mobilidade e necessitou realizar uma ressonância magnética. Para que ela conseguisse chegar até o local de realização do exame, foram-lhe enviadas uma ambulância e uma cadeira de rodas. O princípio do SUS atendido aqui é o da:', '["Universalidade","Equidade","Integralidade","Igualdade","Descentralização"]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'Um pesquisador estudou a relação entre a presença de matas próximas às residências de tutores de cães e a ocorrência de leishmaniose visceral canina. Em 48% dos 87 cães considerados positivos pelo teste rápido, foi relatada a presença do vetor. Já em relação aos 365 cães negativos, em 31 foi relatada a presença dos carrapatos. Nesse caso, o tipo de estudo e o OR são, respectivamente:', '["estudo de caso-controle; 4,84.","estudo transversal; 4,84.","estudo transversal; 10,06.","estudo de caso-controle; 10,06.","estudo de coorte; 6,81."]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'Assinale a alternativa que contém o método diagnóstico para a leptospirose e sua respectiva vantagem.', '["A visualização direta da Leptospira ao microscópio óptico permite a identificação do respectivo serovar.","A cultura para isolamento bacteriano da Leptospira pode ser realizada após terapia antimicrobiana.","O teste de reação em cadeia da polimerase (PCR) possui acurácia mesmo antes da produção de anticorpos antileptospira.","O teste de imunoensaio enzimático ELISA permite a obtenção do resultado em poucas horas.","O teste de aglutinação microscópica (MAT) tem sensibilidade maior que o teste ELISA."]'::jsonb, 3),
  ('Doenças Infecciosas e Parasitárias', 'A cisticercose é a infecção causada pela forma larval de qual tênia?', '["Taenia multiceps","Taenia solium","Taenia ovis","Taenia saginata","Echinococcus granulosus"]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Avalie as afirmações abaixo sobre zoonoses e/ou agentes etiológicos e animais silvestres: 1. Yersinia pestis está associada a roedores e marsupiais. 2. A tuberculose já foi relatada em primatas e psitacídeos. 3. Na leptospirose, há risco de transmissão via contato direto com urina de animais contaminados, principalmente roedores e carnívoros. 4. A transmissão da giardíase pode ocorrer na ingestão de alimentos ou água contaminados com cisticercos.', '["Todas as assertivas estão corretas.","Apenas as assertivas 1, 2 e 3 estão corretas.","Apenas as assertivas 2, 3 e 4 estão corretas.","Apenas as assertivas 2 e 4 estão corretas.","Apenas as assertivas 1 e 3 estão corretas."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'O ciclo de vida da Taenia solium inclui o suíno como hospedeiro intermediário e o ser humano como hospedeiro definitivo. Os seres humanos também podem servir como hospedeiros intermediários e desenvolver a forma cística. Assinale a alternativa correta sobre o complexo teníase-cisticercose.', '["A teníase é adquirida pela ingestão de ovos da tênia.","O meio de transmissão para humanos é o contato direto com animais infectados.","A cisticercose é uma causa importante de epilepsia em países em desenvolvimento.","Cisticercose é uma doença que acomete indivíduos que consomem carne suína crua ou malcozida.","A falta de acesso a medicamentos anti-helmínticos eficazes impede seu controle."]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'Infecções por Toxoplasma gondii são endêmicas no Brasil, onde encontra-se uma das maiores taxas mundiais de infecção por esse agente. Assinale a alternativa que apresenta a via de transmissão responsável pelo maior surto em número de casos já registrado no mundo, ocorrido na cidade de Santa Isabel do Ivaí/PR.', '["Leite.","Frutas.","Carne malcozida.","Verduras e legumes.","Água."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'A esporotricose é uma zoonose de distribuição cosmopolita, principalmente em países tropicais e subtropicais. Sobre essa doença, assinale a alternativa correta.', '["A doença é causada por penetração do agente na derme após feridas cutâneas.","O agente causal da doença é o fungo Tricophyton mentagrophytes.","A doença se desenvolve por contato com fezes de pombos contaminados.","O agente causal da doença é o fungo Cryptococcus neoformans.","A doença se desenvolve pela picada de pulga ou carrapato contaminado."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'O médico veterinário está, desde 2011, entre os profissionais que podem fazer parte do Núcleo de Apoio à Saúde da Família (NASF). São atribuições do médico veterinário no NASF, EXCETO:', '["Visitas domiciliares relacionadas às intersecções entre saúde humana e dos demais animais.","Prevenção, controle e diagnóstico situacional de riscos por zoonoses e doenças de transmissão vetorial.","Identificação e controle de vetores, animais sinantrópicos e animais peçonhentos no território.","Prevenção e controle de enfermidades transmitidas pelos alimentos.","Orientação e prescrição para os tutores de pacientes portadores de doenças com potencial zoonótico."]'::jsonb, 4),
  ('Patologia Geral e Diagnóstico', 'O uso do olfato é importante na necropsia, pois algumas doenças apresentam odores característicos, às vezes quase diagnósticos. Por exemplo, o músculo esquelético de bovinos afetado no carbúnculo sintomático tem um odor distinto de:', '["fossa séptica","manteiga rançosa","sangue","cebola","amônia"]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'Qual mecanismo está envolvido na formação do edema subcutâneo de declive e ascite em casos de reticuloperitonite traumática em bovinos?', '["Inflamação tecidual","Obstrução linfática","Aumento da permeabilidade vascular","Diminuição da pressão oncótica","Aumento da pressão hidrostática"]'::jsonb, 4),
  ('Patologia Geral e Diagnóstico', 'São condições em que se observa a formação de trombos venosos e/ou arteriais, EXCETO:', '["Ingestão de vitamina K","Amiloidose glomerular renal","Metástases de neoplasias sólidas","Coagulação intravascular disseminada","Larvas de Strongylus vulgaris no cavalo"]'::jsonb, 0),
  ('Doenças Infecciosas e Parasitárias', 'O mecanismo de lesão na hemoglobinúria bacilar, que afeta ruminantes, tem um componente local e um sistêmico. A lesão local é a necrose hepatocelular coagulativa, enquanto a lesão sistêmica consiste na lise intravascular de eritrócitos. Em ambos os casos, a lesão é causada pela fosfolipase C e outras enzimas bacterianas. Qual bactéria libera a fosfolipase C na hemoglobinúria bacilar?', '["Clostridium perfringens","Clostridium sordellii","Clostridium septicum","Clostridium haemolyticum","Clostridium chauvoei"]'::jsonb, 3),
  ('Anestesiologia e Farmacologia', 'A solubilidade de um anestésico inalatório no sangue e nos tecidos caracteriza-se pelo seu coeficiente de partição, que descreve a distribuição de um anestésico inalatório entre duas fases ou dois solventes após estabelecido o equilíbrio. Considerando as informações apresentadas, assinale a alternativa correta.', '["Um agente com baixa solubilidade no sangue está associado a um equilíbrio mais rápido, visto que uma quantidade menor de anestésico precisa ser dissolvida no sangue antes de alcançar o equilíbrio com a fase gasosa.","Sevoflurano possui coeficiente de partição sangue/gás maior que o isoflurano.","O coeficiente de partição óleo/gás é inversamente proporcional à potência anestésica.","Um agente anestésico com coeficiente de partição sangue/gás alto permite controle mais preciso da profundidade anestésica.","Um agente anestésico com coeficiente de partição sangue/gás baixo está relacionado a eliminação do anestésico e recuperação mais lentas."]'::jsonb, 0),
  ('Anestesiologia e Farmacologia', 'Um cavalo de 6 anos de idade é admitido na clínica veterinária com sinais de cólica aguda, incluindo inquietação, sudorese excessiva, frequência cardíaca elevada e tentativas frequentes de se deitar e rolar. Após intervenção clínica sem sucesso, o paciente foi encaminhado para cirurgia. Considerando as informações apresentadas, assinale a alternativa correta.', '["A pressão arterial não invasiva fornece acurácia suficiente para manejo anestésico de equinos submetidos à laparotomia.","A dopamina é utilizada como agente vasoativo de primeira linha no tratamento da hipotensão em equinos com cólica.","A bradicardia associada com hipotensão deve ser combatida pela administração de um anticolinérgico, como a efedrina.","A manobra de recrutamento alveolar (MRA) é uma estratégia de ventilação mecânica que resulta em redução significativa do ETCO2.","A lidocaína é comumente administrada pelos seus efeitos anti-inflamatórios e pela sua capacidade de redução da dose do agente inalatório, porém pode não levar à melhora da pressão arterial média (PAM)."]'::jsonb, 4),
  ('Anestesiologia e Farmacologia', 'Um gato de 8 anos de idade será submetido à cirurgia de profilaxia oral e extração dentária. Na anamnese, o tutor relata que o animal tem asma felina, caracterizada por episódios de tosse e dispneia, e está sob tratamento com prednisolona. O exame clínico indica que o gato está estável, mas apresenta sinais leves de tosse e sibilos à auscultação pulmonar. Assinale a alternativa correta.', '["Para controle da dor e inflamação pós-operatória, deve-se prescrever meloxicam e dipirona.","A acepromazina é contraindicada nesses pacientes, por estimular a liberação de histamina.","Deve-se considerar uma radiografia torácica pré-operatória para ver a condição da doença do parênquima pulmonar antes da anestesia.","Devem ser evitados opioides com o potencial de aumentar a liberação de histamina, como o fentanil intravenoso.","A inclusão de um anticolinérgico no momento da medicação pré-anestésica é contraindicada, em decorrência do seu efeito broncoconstritor."]'::jsonb, 2),
  ('Anestesiologia e Farmacologia', 'A compreensão da fisiopatologia da dor e o diagnóstico da dor nos animais são essenciais para o seu manejo eficaz. Sobre esse assunto, assinale a alternativa correta.', '["A fisiopatologia da dor é caracterizada por um processo linear e unidimensional, abrangendo transdução, transmissão, modulação e percepção da dor.","Os opioides são efetivos no controle da dor por bloquearem a geração de estímulos nocivos.","A gabapentina é usada comumente para tratar a dor aguda pós-operatória de origem somática.","Escala descritiva simples, escala numérica simples e escala visual analógica constituem sistemas de pontuação unidimensionais da dor.","A Escala de Liverpool para cães, o Índice de Helsinki e o Inventário canino breve de dor são exemplos de escalas de avaliação de dor aguda."]'::jsonb, 3),
  ('Patologia Geral e Diagnóstico', 'Imagens radiográficas em duas projeções exemplificam um procedimento cirúrgico. De acordo com as imagens (fratura/afecção de joelho tratada cirurgicamente), assinale a alternativa que apresenta respectivamente os nomes da técnica e da afecção para qual foi usada.', '["Avanço da tuberosidade tibial – Ruptura do ligamento cruzado cranial.","Osteotomia de nivelamento do platô tibial – Ruptura do ligamento cruzado cranial.","Placa de compressão – Fratura proximal de tíbia.","Placa de neutralização – Deformidade angular.","Placa de apoio – Fratura metafisária tibial."]'::jsonb, 1),
  ('Clínica e Cirurgia de Pequenos Animais', 'Dentro dos princípios de assepsia cirúrgica, o nível de desinfecção ou esterilidade depende da função a que se destina o instrumento ou dispositivo médico. Considerando as informações apresentadas, fio de sutura é um material classificado em que nível de esterilidade ou desinfecção?', '["Crítico","Semicrítico","Não crítico","Inócuo","Estéril"]'::jsonb, 0),
  ('Clínica e Cirurgia de Pequenos Animais', 'Considere um gato com indicação para enterotomia e com níveis séricos de albumina dentro dos valores de referência. Qual dos fios cirúrgicos indicados abaixo é o mais adequado para enterorrafia desse paciente?', '["Cat gut.","Ácido poliglicólico.","Polidioxanona.","Poliglactina 910.","Poliéster."]'::jsonb, 2),
  ('Clínica e Cirurgia de Pequenos Animais', 'A hérnia perineal é uma doença comum em cães machos intactos. Existem várias técnicas cirúrgicas descritas para correção, porém, na herniorrafia tradicional anatômica, sugere-se a incorporação do ligamento sacrotuberoso. Essa etapa do procedimento cirúrgico pode resultar em uma grave complicação. Assinale a alternativa que corresponde à complicação inerente a essa etapa da técnica.', '["Laceração dos sacos anais.","Aprisionamento do nervo femoral.","Laceração da uretra.","Aprisionamento do nervo isquiático.","Laceração do plexo gluteal."]'::jsonb, 3),
  ('Clínica e Cirurgia de Pequenos Animais', 'Segundo a classificação IRIS (International Renal Interest Society) para doença renal crônica (DRC) em cães e gatos, os pacientes nefropatas podem ser classificados em estágios de I a IV. Sobre doença renal crônica em cães e gatos, assinale a alternativa correta.', '["A azotemia é o que determina o estadiamento da doença, sendo o estágio I a presença de uma azotemia leve: aumento leve da creatinina (acima de 1,4 mg/dL em cães e 1,6 mg/dl em gatos).","A avaliação da proteinúria (uma subclassificação do estadiamento IRIS) é realizada através da razão proteína urinária:creatinina urinária, devendo ser observada em exames seriados, e não apenas em uma amostra isolada.","A presença ou não da hipertensão arterial sistêmica é uma subclassificação do estadiamento IRIS, cujo tratamento deve ser instituído apenas para animais comprovadamente hipertensos e com lesão hipertensiva em órgão-alvo.","A creatinina, por ser um biomarcador altamente específico e sensível, é utilizada para o diagnóstico precoce da DRC em cães e gatos.","Mais de um mecanismo pode estar envolvido na anemia presente em animais com DRC, sendo a diminuição da eritropoetina sérica um importante fator, causado pela perda urinária excessiva deste hormônio."]'::jsonb, 1),
  ('Clínica e Cirurgia de Pequenos Animais', 'A doença mixomatosa valvar mitral (DMVM) é a doença cardíaca mais comum em cães em muitas partes do mundo. A regurgitação causada pelo não fechamento adequado da valva mitral durante a sístole provoca consequências hemodinâmicas que culminam com a insuficiência cardíaca congestiva (ICC). Sobre o diagnóstico e a terapêutica da DMVM em cães, assinale a alternativa correta.', '["Pacientes em estágio B1 são assintomáticos, enquanto aqueles classificados como B2 já possuem sinais de ICC esquerda, como edema pulmonar.","A identificação de um paciente com DMVM em estágio A permite o início precoce do tratamento, como a instituição da dieta hipossódica.","À medida que o quadro degenerativo progride, o aumento do volume de sangue no átrio esquerdo causa uma hipertrofia concêntrica, que reduz ainda mais o débito cardíaco.","A tosse e o cansaço fácil, comumente observados em pacientes com DMVM, ocorrem devido à bradicardia que esses pacientes desenvolvem em decorrência do estiramento excessivo das fibras cardíacas.","A relação átrio esquerdo:aorta aumentada (mensurada no início da diástole em um exame ecocardiográfico) é um dos critérios que indicam o estágio B2."]'::jsonb, 4),
  ('Doenças Infecciosas e Parasitárias', 'Sobre as principais doenças infecciosas em cães e gatos, assinale a alternativa correta.', '["A peritonite infecciosa felina (PIF) é uma doença desencadeada por formas mutadas do coronavírus felino (FCoV).","A apresentação clássica de diarreia com sangue observada em cães com parvovirose ocorre devido à vasculite causada pela replicação viral nos vasos sanguíneos.","A trombocitopenia é uma alteração patognomônica da erliquiose canina.","Entre os diagnósticos diferenciais para um gato ictérico, está a micoplasmose hemotrópica felina: essa bactéria é o principal agente etiológico da tríade felina, causando uma grave hepatopatia.","A cinomose canina é uma doença altamente contagiosa e tem como principal mecanismo de transmissão a contaminação fecal-oral."]'::jsonb, 0),
  ('Clínica e Cirurgia de Pequenos Animais', 'Afecções neurológicas apresentam sinais clínicos característicos envolvendo a alteração de nervos cranianos e lesões medulares que geralmente afetam a locomoção. Diante do exposto, assinale a alternativa correta:', '["Um paciente canino, macho, dachshund de 5 anos, com queixa de paraparesia não ambulatória aguda, tem como diagnóstico diferencial mais provável a doença de disco intervertebral tipo II.","Crises convulsivas em cães e gatos podem ser tratadas a longo prazo com medicamentos antiepiléticos como o fenobarbital ou o diazepam oral.","Déficits proprioceptivos indicam lesões neurológicas e permitem a localização da lesão em sistema nervoso periférico ou central.","Tetraparesias flácidas podem ocorrer devido a miastenia gravis, botulismo ou síndrome da cauda equina.","A síndrome vestibular pode ser central ou periférica, as quais podem ser diferenciadas porque na periférica não ocorrem déficits proprioceptivos nem sonolência, podendo ocorrer a síndrome de Horner."]'::jsonb, 4),
  ('Clínica Médica de Grandes Animais', 'A laminite em equinos é uma afecção multifatorial que cursa com alto grau de dor e comprometimento mecânico com prognóstico reservado a desfavorável, sendo o exame radiográfico uma avaliação indispensável para diagnóstico e adequada conduta terapêutica. Em relação à laminite em equinos, assinale a alternativa correta.', '["As projeções radiográficas para avaliação das alterações da terceira falange em equinos portadores de laminite são a lateromedial e a ventro-proximal-palmaro-proximal de 45º.","Na projeção radiográfica lateromedial, deve-se colocar um objeto radiopaco na região dorsal da muralha do casco para auxiliar na avaliação do grau de rotação da falange distal.","Os sinais radiográficos de laminite são calcificação das cartilagens alares e área de radioluscência no sesamoide distal.","A radiografia na posição ventro-proximal-palmaro-proximal de 45º é a melhor para se avaliar o grau de alteração das lâminas dérmicas em cavalos portadores de laminite.","Apesar de o exame radiográfico dar informações importantes sobre a evolução da laminite, o hemograma é o exame complementar mais fidedigno na avaliação da gravidade da afecção, principalmente quando crônica."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'As deformidades angulares em potros podem ser afecções relativamente frequentes em animais jovens, comprometendo seu crescimento e levando a alterações graves que podem cursar com limitação na deambulação e incapacidade para o esporte. Em relação às deformidades angulares, assinale a alternativa correta.', '["A deformidade angular do tipo valgo corresponde ao desvio medial do membro distal à origem da deformidade.","As deformidades angulares podem ser de origem congênita ou adquirida.","Entre as causas congênitas para as deformidades angulares, está a consanguinidade.","A ossificação prematura intrauterina é uma importante causa para o desenvolvimento das deformidades angulares.","O tratamento conservador para as deformidades angulares deve preconizar o exercício durante a fase de crescimento do potro, soltando-o em piquetes para melhor desenvolvimento ósseo e correção do desvio."]'::jsonb, 1),
  ('Clínica Médica de Grandes Animais', 'A síndrome cólica constitui uma das principais causas de atendimento veterinário de emergência em equinos. Um dos compartimentos que podem ser acometidos é o cólon maior, que pode sofrer com compactações que constituem um tipo de obstrução não estrangulativa desse segmento. Com relação à compactação de cólon maior em equinos, assinale a alternativa correta.', '["É uma alteração desenvolvida a partir do excesso de carga parasitária pelo Parascaris equorum, cujas larvas podem obstruir o intestino de equinos provocando as compactações.","Apresenta manifestação de dor normalmente intensa e não responsiva a analgésicos, podendo a cirurgia ser necessária em casos de obstruções completas com muita desidratação do conteúdo colônico.","É uma alteração relacionada ao manejo alimentar com poucas refeições ao dia compostas de concentrado e pouca forragem, o que induz a um desvio de líquido do cólon maior para a circulação sistêmica, reduzindo a hidratação do conteúdo colônico e favorecendo a formação da compactação.","Pode ter o tratamento conservador inicialmente com a tentativa de administração exclusiva de óleo mineral e sulfato de magnésio via retal.","É uma condição que pode ser tratada pelo método conservador, sendo que o tratamento cirúrgico ou invasivo não é indicado para essa afecção."]'::jsonb, 2),
  ('Clínica Médica de Grandes Animais', 'A doença pulmonar obstrutiva crônica (DPOC) em equinos é uma afecção limitante para o desempenho atlético e a qualidade de vida desses animais. Para o diagnóstico dessa doença, são indispensáveis exames complementares como a análise e a cultura do lavado broncoalveolar. Em relação à DPOC, assinale a alternativa correta.', '["A DPOC é uma doença viral comum em equinos confinados, sendo altamente contagiosa por ser transmitida por aerossóis, sendo a vacinação a mais importante medida para prevenção da doença.","Animais acometidos com DPOC têm esforço respiratório evidente, especialmente uma dispneia inspiratória, podendo ou não haver tosse.","Equinos com DPOC normalmente não possuem secreção nasal ou tosse, sendo caracterizada por uma doença alérgica causada por alguns tipos de pastagens em animais criados em regime extensivo.","A DPOC é uma doença crônica grandemente associada à estabulação e à exposição a ambientes pouco arejados, feno, palha e à presença de fungos no ambiente.","A DPOC é uma doença bacteriana altamente contagiosa, causada pelo Streptococcus equi, caracterizada por tosse produtiva, linfadenopatia submandibular e secreção nasal mucopurulenta."]'::jsonb, 3),
  ('Patologia Geral e Diagnóstico', 'Sobre os princípios da interpretação radiográfica do esqueleto apendicular, assinale a alternativa correta.', '["O exame radiográfico de extremidades em cães e gatos deve consistir em um mínimo de três projeções ortogonais, duas projeções laterais e uma craniocaudal (dorsopalmar, dorsoplantar).","A agressividade de uma lesão óssea é baseada na avaliação de três critérios: se há ou não destruição cortical; o caráter de qualquer reação periosteal; a distinção do limite entre a lesão óssea e o osso normal, chamado de zona de transição.","Existem muitos casos no equino em que as projeções lateral e craniocaudal (dorsopalmar, dorsoplantar) de um membro são suficientes.","A lise óssea geográfica é uma região grande e relativamente mal definida de perda óssea; padrões \"roídos de traças\" e perceptivos descrevem focos menores de lise óssea.","Uma reação periosteal ativa é uma característica de muitas lesões ósseas agressivas e é aquela em que a margem da reação periosteal é irregular e suave."]'::jsonb, 1),
  ('Patologia Geral e Diagnóstico', 'Lesão ultrassonográfica da vesícula biliar distendida, com um padrão de estrias hiperecoicas irradiando em direção ao seu centro, apresentando a área hiperecoica central heterogênea e completamente imóvel, com descrição semelhante a um padrão semelhante a um kiwi. Esse tipo de lesão é compatível com qual possível diagnóstico?', '["Mucocele biliar completa ou madura","Lama biliar","Colecistite","Mucocele biliar incompleta","Cálculo biliar com obstrução"]'::jsonb, 0),
  ('Patologia Geral e Diagnóstico', 'A lesão ultrassonográfica com espessamento do endométrio, acompanhada de lesões císticas embutidas na parede uterina, é compatível com qual possível diagnóstico?', '["Prenhez","Morte fetal","Hiperplasia endometrial cística","Piometra","Endometrite"]'::jsonb, 2),
  ('Doenças Infecciosas e Parasitárias', 'Em regiões onde a hemoncose é endêmica, frequentemente pode ser observado que, após um período de chuvas intensas, a contagem de ovos nas fezes de ruminantes infectados pelo H. contortus cai para níveis próximos a zero. Considerando a informação apresentada, assinale a alternativa correta.', '["Isso ocorre pelo nível de imunidade que os ruminantes adquirem, pois, no período chuvoso, a contaminação é intensa, e os animais acabam desenvolvendo resposta imune eficiente.","A eliminação da população de parasitas em consequência de uma reação de hipersensibilidade do tipo imediata a antígenos derivados das larvas existentes no abomaso é o fenômeno conhecido como autocura.","Após as chuvas, a proliferação de larvas é intensa, e, como há uma competição pela comida, as larvas diminuem a postura de ovos, pois não têm energia suficiente para produzi-los.","A parasitemia do Haemonchus spp. comumente diminui nos períodos pós chuva por conta do fenômeno da anidrobiose.","Os valores do O.P.G. nos exames de fezes podem ser encontrados em baixíssimos níveis nesse período, por conta da diminuição de larvas infectantes, atraídas pelo hidrotropismo positivo nos parasitas adultos removidos pela água da chuva abundante."]'::jsonb, 1),
  ('Doenças Infecciosas e Parasitárias', 'Quanto às infecções causadas por cestodas nos animais domésticos, é correto afirmar que:', '["essa classe de parasitas produz ovos que, quando desenvolvidos, contêm uma larva de primeiro estágio, a oncosfera, que é a forma infectante para o hospedeiro intermediário, presente em praticamente todos os ciclos biológicos dessa classe.","as tênias do gênero Echinococcus sp. são caracterizadas por apresentarem seu tamanho variado, podendo atingir até 60-80 cm, e seus ovos, liberados com as fezes dos hospedeiros intermediários, poderão ser ingeridos acidentalmente pelos cães, que desenvolverão o cisto hidático.","os escólices da Moniezia sp. se prendem fortemente à mucosa rumenal, na qual causam áreas de inflamação, mas não produzem intensa reação patogênica e podem ser visualizados nas fezes com certa frequência.","no ciclo de vida do Dipylidium caninum, os ovos liberados nas fezes formam cápsulas ovígeras, que são absorvidas pelas pulgas, cuja forma cercoide penetra no cão no momento em que ele se coça.","o Anoplocephala spp. normalmente é transmitido pela ingestão de ácaros presentes na ração contaminada; a forma larval aloja-se na saída do estômago e próximo ao piloro, causando lesões de mucosas, uma das principais causas de cólica nos equídeos."]'::jsonb, 0),
  ('Doenças Infecciosas e Parasitárias', 'Podem ser identificados como principais causadores de infecções por protozoários intestinais nos animais de companhia, os patógenos:', '["Eimeria sp. e Cryptosporidium spp.","Isospora spp. e Toxascaris sp.","Neospora e Toxoplasma","Giardia intestinalis e Cystoisospora sp.","Haemobartonella felis e Giardia sp."]'::jsonb, 3),
  ('Doenças Infecciosas e Parasitárias', 'As infestações por Ixodídeos têm se tornado um grande problema para os animais de companhia: além de causarem irritação, podem transmitir muitas doenças, principalmente para os cães e até mesmo ao homem. Assinale a alternativa correta quanto a essa família de parasitas.', '["Durante a fase de vida livre, as larvas desses parasitas escondem-se no bolo fecal e, quando em condições favoráveis, misturam-se com a vegetação, podendo ser ingeridas acidentalmente, atingindo assim o hospedeiro para fechar seu ciclo de vida.","Vários gêneros de parasitas compõem essa grande família, que tem como destaque a Ctenocephalides sp., que também é um importante vetor de doenças como a dirofilariose.","O fato de o Rhipicephalus sanguineus ser um parasita de ciclo trioxeno aumenta muito a chance de ele infectar novos hospedeiros com doenças transmitidas pelo hematofagismo de suas fases de vida.","A leishmaniose visceral é uma das doenças que podem ser transmitidas pela picada desses parasitas, que inoculam a forma infectante na corrente sanguínea, a qual rapidamente se multiplica quando o hospedeiro começa a se coçar.","A sarna otodécica pode causar, além da irritação pelas constantes picadas no hospedeiro, uma lesão importante no pavilhão auricular, conhecida como otohematoma, cujo tratamento necessário pode ser um procedimento cirúrgico."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'A retirada da unidade analítica é a primeira etapa da análise microbiológica de produtos de origem animal. A unidade analítica é:', '["a quantidade de amostras de um mesmo lote.","a quantidade de material retirado de uma amostra.","a quantidade de diluições decimais requeridas.","o volume da diluição decimal utilizado na semeadura em placas.","o procedimento de homogeneização da amostra."]'::jsonb, 1),
  ('Saúde Pública e Legislação Veterinária', 'A contagem de Staphylococcus coagulase positiva em produtos de origem animal está sujeita a vários procedimentos, entre eles, o teste da coagulase livre. Esse teste:', '["permite diferenciar Staphylococcus enterotoxigênicos dos não enterotoxigênicos.","permite diferenciar Staphylococcus aureus das demais espécies.","permite dar uma indicação de patogenicidade entre as espécies de Staphylococcus.","permite resultados rápidos, em até 30 minutos.","é um teste conhecido também pela denominação \"clumping factor\"."]'::jsonb, 2),
  ('Saúde Pública e Legislação Veterinária', 'Além da água peptonada tamponada, são meios de cultura utilizados no protocolo analítico para a detecção de Salmonella sp. em produtos de origem animal:', '["caldo tetrationato, caldo Rappaport Vassiliadis, ágar xilose lisina desoxicolato.","caldo tetrationato, caldo Rappaport Vassiliadis, ágar Baird-Parker.","caldo tetrationato, ágar lisina ferro, ágar vermelho violeta bile glicose.","ágar tripticase de soja extrato de levedura, caldo Rappaport Vassiliadis, ágar tríplice açúcar ferro.","ágar tripticase de soja extrato de levedura, ágar Baird-Parker, ágar vermelho violeta bile glicose."]'::jsonb, 0),
  ('Saúde Pública e Legislação Veterinária', 'Os protocolos de detecção de Listeria monocytogenes em produtos de origem animal requerem uma etapa de confirmação bioquímica com base na fermentação de açúcares. Além de xilose e rhamnose, os açúcares utilizados nessa etapa de confirmação são:', '["dextrose e lactose.","dextrose e manitol.","dextrose e sacarose.","lactose e sacarose.","manitol e sacarose."]'::jsonb, 1),
  ('Patologia Geral e Diagnóstico', 'Para realização do hematócrito, a amostra sanguínea é transferida para um capilar que é selado em uma das extremidades e submetido à centrifugação em altas velocidades. Considerando que, para leitura do resultado, a extremidade selada será a inferior, assinale a alternativa correta.', '["Após a centrifugação, na porção superior do capilar, encontram-se os leucócitos.","A amostra de sangue total apresentará duas camadas após a centrifugação.","Fisiologicamente, o plasma apresentará coloração avermelhada.","Por meio dessa técnica, obtém-se a porcentagem do sangue total composta pelos eritrócitos.","A centrifugação é necessária para que o plasma se distribua entre as células sanguíneas."]'::jsonb, 3),
  ('Patologia Geral e Diagnóstico', 'Considere que policitemia refere-se ao aumento do número de hemácias, do hematócrito ou da concentração de hemoglobina. Assinale a alternativa que apresenta respectivamente os resultados esperados para pressão de oxigênio (PaO2) e concentração de eritropoietina em um paciente com policitemia por produção inapropriada de eritropoietina.', '["Normal; Aumentada.","Diminuída; Normal.","Aumentada; Normal.","Normal; Diminuída.","Diminuída; Diminuída."]'::jsonb, 0),
  ('Fisiologia e Ciências Básicas', 'Os rins reabsorvem mais de 99% da água que entra nos túbulos. Assinale a alternativa que apresenta alteração que diminua a concentração da urina.', '["A presença de pelo menos um terço da massa renal funcional.","Aumento da produção hepática de ureia.","Diminuição da produção de hormônio antidiurético (ADH).","Desidratação.","Aumento da reatividade dos receptores do ADH."]'::jsonb, 2),
  ('Patologia Geral e Diagnóstico', 'Para interpretar os testes enzimáticos séricos utilizados na detecção de doença hepática, é necessário conhecimento básico de enzimologia diagnóstica. Assinale a alternativa que apresenta um dos princípios básicos da enzimologia diagnóstica.', '["A enzima tem valor diagnóstico quando estiver presente em vários órgãos.","Quanto maior a atividade sérica da enzima, menor será a sua presença na corrente sanguínea.","Para a enzima ter valor diagnóstico, o tecido lesionado deverá diminuir a produção da referida enzima.","A enzimologia diagnóstica propicia informação a respeito da função tecidual.","O aumento da atividade sérica da enzima ocorre por extravasamento das células lesionadas ou por aumento de sua produção."]'::jsonb, 4),
  ('Clínica e Cirurgia de Pequenos Animais', 'Imagens de um cachorro-do-mato (Cerdocyon thous) com fratura bilateral de rádio e ulna. Dentre as técnicas passíveis de aplicação, indique a que representa um erro técnico grave tanto para cachorros-do-mato quanto para cães domésticos.', '["Uso exclusivo de placa metálica bloqueada em ambos os rádios.","Uso de placa bloqueada no rádio e pino intramedular na ulna, para ambos os lados.","Uso de fixador esquelético externo tipo 2 no rádio, para ambos os lados.","Uso de fixador esquelético externo associado a pino intramedular no rádio.","Uso de fixador esquelético externo circular no rádio, para ambos os lados."]'::jsonb, 3),
  ('Patologia Geral e Diagnóstico', 'Assinale a alternativa que indica corretamente a que espécie animal pertence uma dada radiografia de pequeno mamífero de estimação apresentada na prova.', '["Chinchila (Chinchila lanigera)","Rato (Rattus rattus)","Coelho (Oryctolagus cuniculus)","Porquinho-da-índia (Cavia porcellus)","Hamster (Mus musculus)"]'::jsonb, 2),
  ('Clínica e Cirurgia de Pequenos Animais', 'Imagens demonstram o processo de consolidação óssea do tarsometatarso em um filhote de coruja-suindara (Tyto furcata), sendo uma imagem o pós-operatório imediato, e a outra, o pós-operatório de 14 dias. Assinale a alternativa que indica a técnica de osteossíntese empregada nesse caso.', '["Pino intramedular","Fixador esquelético externo tipo 1A","Fixador esquelético externo tipo 1B","Fixador esquelético externo tipo 2","Fixador esquelético tipo 3"]'::jsonb, 3),
  ('Clínica e Cirurgia de Pequenos Animais', 'Sobre contenção de animais silvestres, considere: 1. Queixadas e catetos podem ser contidos fisicamente pelos membros pélvicos e focinho. 2. A contenção de cutias em cativeiro pode ser facilitada pela utilização de abrigos tipo manilha, ao se posicionar saco fundo de tecido de algodão em uma das extremidades do abrigo para onde o animal pode ser conduzido. 3. Na contenção de lontras com o uso de puçás, deve-se cuidar para não gerar fraturas dentárias. 4. Na contenção física de passeriformes, deve-se posicionar a cabeça da ave entre dois dedos do manipulador, e a região peitoral da ave deve ser firmemente segura para evitar fraturas. Assinale a alternativa correta.', '["Apenas a afirmativa 1 é verdadeira.","Apenas as afirmativas 1 e 4 são verdadeiras.","Apenas as afirmativas 2 e 3 são verdadeiras.","Apenas as afirmativas 2, 3 e 4 são verdadeiras","As afirmativas 1, 2, 3 e 4 são verdadeiras."]'::jsonb, 2);
